INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'GitHub Copilot Certification', N'<h3>Summary</h3> <p>This certification validates your expertise with GitHub Copilot.</p> <h3>Skills Measured</h3> <ul> <li>Responsible AI</li> <li>GitHub Copilot plans and features</li> <li>How GitHub Copilot works and handles data</li> <li>Prompt Crafting and Prompt Engineering</li> <li>Developer use cases for AI</li> <li>Testing with GitHub Copilot</li> <li>Privacy fundamentals and content exclusions</li> </ul> <p><a href="https://examregistration.github.com/certification/COPILOT">Go to Certification Page</a></p>', SYSDATETIME(), 11);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Building Applications with GitHub Copilot Agent Mode', N'<h3>Summary</h3> <p>Learn how to build applications using GitHub Copilot Agent Mode by prompting autonomous development tasks, using documentation for guidance, and understanding how Agent Mode iteratively manages, refactors, and improves your codebase.</p> <h3>Learning Objectives</h3> <p>In this module, you''ll:</p> <ul> <li>Understand how to develop with VS Code IDE in a GitHub Codespace.</li> <li>Prompt GitHub Copilot agent mode to create an application.</li> <li>Leverage documentation files to instruct GitHub Copilot agent mode.</li> <li> <p>Understand how GitHub Copilot agent mode iterates over a code base to:</p> </li> <li> <p>Fix errors</p> </li> <li>Refactor code</li> <li>Develop new features</li> </ul> <p><a href="https://learn.microsoft.com/en-us/training/modules/github-copilot-agent-mode/">Go to Learning Module</a></p>', SYSDATETIME(), 10);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Challenge GitHub Copilot with SQL', N'<h3>Summary</h3> <p>Demonstrate your ability to apply advanced GitHub Copilot features to interact with an application that uses complex SQL queries.</p> <h3>Learning Objectives</h3> <ul> <li>Demonstrate an understanding of how to use GitHub Copilot with existing application and SQL code.</li> <li>Use advanced GitHub Copilot interaction techniques to deal with complex problems regarding SQL queries.</li> <li>Iterate, validate, and refine answers to get better and more accurate suggestions.</li> <li>Gain an understanding of GitHub Copilot prompting techniques and how prompts impact the output.</li> </ul> <h3>Prerequisites</h3> <ul> <li>A basic understanding of SQL and relational databases.</li> <li>Familiarity with GitHub and GitHub Codespaces.</li> </ul> <p><a href="https://learn.microsoft.com/en-us/training/modules/challenge-github-copilot-sql/">Go to Learning Module</a></p>', SYSDATETIME(), 10);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Challenge Project - Build a Minigame with GitHub Copilot and .NET', N'<h3>Summary</h3> <p>Demonstrate your ability to analyze, create, and use different methods to develop a console minigame in .NET with GitHub Codespaces and GitHub Copilot.</p> <h3>Learning Objectives</h3> <ul> <li>Experience GitHub Codespaces as a development environment.</li> <li>Develop input and output routines in a .NET console application.</li> <li>Use GitHub Copilot as an assistant.</li> </ul> <p><a href="https://learn.microsoft.com/en-us/training/modules/challenge-project-create-mini-game-with-copilot-dotnet/">Go to Learning Module</a></p>', SYSDATETIME(), 10);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Challenge Project - Build a Minigame with GitHub Copilot and Python', N'<h3>Summary</h3> <p>Demonstrate your ability to analyze, create, and use different methods to develop a console minigame in Python with GitHub Codespaces and GitHub Copilot.</p> <h3>Learning Objectives</h3> <ul> <li>Experience GitHub Codespaces as a development environment.</li> <li>Develop input and output routines in a Python console application.</li> <li>Use GitHub Copilot as an assistant.</li> </ul> <p><a href="https://learn.microsoft.com/en-us/training/modules/challenge-project-create-mini-game-with-copilot/">Go to Learning Module</a></p>', SYSDATETIME(), 10);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Develop Code Features Using GitHub Copilot Tools', N'<h3>Summary</h3> <p>This module explores using GitHub Copilot and GitHub Copilot Chat suggestions to create new code. Autocompletion and code update suggestions are generated, managed, and implemented using the GitHub Copilot extensions for Visual Studio Code.</p> <h3>Learning Objectives</h3> <p>By the end of this module, you''re able to:</p> <ul> <li>Generate autocompletion suggestions based on code and code comments using the GitHub Copilot extension for Visual Studio Code.</li> <li>Manage autocompletion suggestions by accepting, partially accepting, and dismissing suggestions.</li> <li>Create chat prompts/questions that communicate your intent by using a combination of chat participants, slash commands, chat variables, and natural language text.</li> <li>Create new code using the Chat View, Inline Chat, Quick Chat, and Smart Actions features provided by the GitHub Copilot Chat extension for Visual Studio Code.</li> <li>Manage code update suggestions by accepting, partially accepting, editing, and discarding the suggestions generated by GitHub Copilot Chat.</li> </ul> <p><a href="https://learn.microsoft.com/en-us/training/modules/develop-code-features-using-github-copilot-tools/">Go to Learning Module</a></p>', SYSDATETIME(), 10);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Develop Unit Tests Using GitHub Copilot Tools', N'<h3>Summary</h3> <p>This module explores using GitHub Copilot and GitHub Copilot Chat to create unit tests. Exercises provide practical experience creating unit test projects and running unit tests in Visual Studio Code.</p> <h3>Learning Objectives</h3> <p>By the end of this module, you''re able to:</p> <ul> <li>Create unit tests using the GitHub Copilot and GitHub Copilot Chat extensions for Visual Studio Code.</li> <li>Create unit tests that target edge cases and specific conditions using the GitHub Copilot and GitHub Copilot Chat extensions for Visual Studio Code.</li> <li>Use Visual Studio Code, the .NET SDK, and the C# Dev Kit extension to create a test project and verify that your unit tests build and run successfully.</li> </ul> <p><a href="https://learn.microsoft.com/en-us/training/modules/develop-unit-tests-using-github-copilot-tools/">Go to Learning Module</a></p>', SYSDATETIME(), 10);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Developer Use Cases for AI with GitHub Copilot', N'<h3>Summary</h3> <p>This module explores how GitHub Copilot streamlines developer productivity through AI-powered features. It enhances the Software Development Life Cycle (SDLC), aligns with developer preferences, and identifies key limitations. Additionally, it measures productivity gains effectively.</p> <h3>Learning Objectives</h3> <p>By the end of this module, you''re able to:</p> <ul> <li>Identify specific ways GitHub Copilot integrates seamlessly into developer workflows, enhancing the overall development experience and supporting individual coding preferences.</li> <li>Explore GitHub Copilot''s potential impact on different stages of the Software Development Lifecycle.</li> <li>Evaluate the limitations of AI-assisted coding and measure its impact on development efficiency.</li> </ul> <p><a href="https://learn.microsoft.com/en-us/training/modules/developer-use-cases-for-ai-with-github-copilot/">Go to Learning Module</a></p>', SYSDATETIME(), 10);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Generate Documentation Using GitHub Copilot Tools', N'<h3>Summary</h3> <p>This module explores the generation of code explanations, project documentation, and inline code comment documentation using the GitHub Copilot Chat extension for Visual Studio Code.</p> <h3>Learning Objectives</h3> <p>By the end of this module, you''ll be able to:</p> <ul> <li>Generate explanations of code blocks, code files, and entire code workspaces using the GitHub Copilot Chat extension for Visual Studio Code.</li> <li>Generate code project documentation using the GitHub Copilot Chat extension for Visual Studio Code.</li> <li>Generate inline code documentation using the GitHub Copilot Chat extension for Visual Studio Code.</li> </ul> <p><a href="https://learn.microsoft.com/en-us/training/modules/generate-documentation-using-github-copilot-tools/">Go to Learning Module</a></p>', SYSDATETIME(), 10);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Get Started with GitHub Copilot', N'<h3>Summary</h3> <p>This module introduces developers to the GitHub Copilot products, the benefits that GitHub Copilot provides to developers, the GitHub Copilot and GitHub Copilot Chat product features, and the GitHub Copilot extensions for Visual Studio Code.</p> <h3>Learning Objectives</h3> <p>By the end of this module, you''ll be able to:</p> <ul> <li>Explain what GitHub Copilot is and the advantages it provides.</li> <li>Install the GitHub Copilot extensions for Visual Studio Code.</li> <li>Explain the features of the GitHub Copilot extensions for Visual Studio Code and how to use them.</li> <li>Configure the GitHub Copilot extensions for Visual Studio Code.</li> </ul> <p><a href="https://learn.microsoft.com/en-us/training/modules/get-started-github-copilot/">Go to Learning Module</a></p>', SYSDATETIME(), 10);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'GitHub Copilot Across Environments: IDE, Chat, and Command Line Techniques', N'<h3>Summary</h3> <p>Explore the multifaceted capabilities of GitHub Copilot across various development environments. Learn to harness AI-assisted coding in your IDE, engage in natural language conversations for complex tasks, and enhance your command-line productivity.</p> <h3>Learning Objectives</h3> <p>At the end of this module, you''ll be able to:</p> <ul> <li>Understand how to utilize GitHub Copilot''s auto-suggestions, multiple suggestions pane, and its ability to adapt to different coding styles.</li> <li>Understand how to provide context to GitHub Copilot through inline comments, block comments, doc strings, and other types of comments to enhance code generation accuracy.</li> <li>Understand how to interact with GitHub Copilot through natural language conversations to generate complex code, debug issues, and obtain code explanations in real-time.</li> <li>Understand how to improve the relevance of GitHub Copilot Chat''s suggestions by using scope referencing, slash commands, and agents.</li> <li>Understand how to interact with GitHub Copilot in CLI to get command explanations, suggestions, and even execute commands based on specific needs.</li> </ul> <p><a href="https://learn.microsoft.com/en-us/training/modules/github-copilot-across-environments/">Go to Learning Module</a></p>', SYSDATETIME(), 10);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Guided Project - Accelerate App Development Using GitHub Copilot Tools', N'<h3>Summary</h3> <p>This module explores using GitHub Copilot to accelerate development of an end-to-end project. GitHub Copilot is used to explain unfamiliar code, generate project documentation, develop a new app feature, develop unit tests, and implement improvements.</p> <h3>Learning Objectives</h3> <p>By the end of this module, you''re able to:</p> <ul> <li>Explain an unfamiliar codebase using GitHub Copilot tools.</li> <li>Generate README project documentation using GitHub Copilot tools.</li> <li>Develop a new application feature using GitHub Copilot tools.</li> <li>Create unit tests using GitHub Copilot tools.</li> <li>Implement code quality, reliability, performance, and security improvements using GitHub Copilot tools.</li> </ul> <p><a href="https://learn.microsoft.com/en-us/training/modules/guided-project-accelerate-app-development-using-github-copilot-tools/">Go to Learning Module</a></p>', SYSDATETIME(), 10);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Implement Code Improvements Using GitHub Copilot Tools', N'<h3>Summary</h3> <p>This module explores using GitHub Copilot Chat to develop improvements for an existing codebase. Exercises provide practical experience implementing GitHub Copilot suggestions that improve code quality, reliability, performance, and security.</p> <h3>Learning Objectives</h3> <p>By the end of this module, you''re able to:</p> <ul> <li>Develop prompts/questions for GitHub Copilot Chat that help you to improve the code in your existing code projects.</li> <li>Implement code update suggestions from GitHub Copilot Chat that improve existing code in the areas of code quality, reliability, performance, and security.</li> </ul> <p><a href="https://learn.microsoft.com/en-us/training/modules/implement-code-improvements-using-github-copilot-tools/">Go to Learning Module</a></p>', SYSDATETIME(), 10);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Introduction to GitHub Copilot Enterprise', N'<h3>Summary</h3> <p>Learn about the differences between GitHub Copilot for Enterprise, for Business, and for Individuals. Examine specific use cases, including how to enable and use GitHub Copilot Enterprise.</p> <h3>Learning Objectives</h3> <p>By the end of this module, you''ll be able to:</p> <ul> <li>Understand what the GitHub Copilot Enterprise plan is.</li> <li>Understand the differences between GitHub Copilot Enterprise versus Business versus Individual.</li> <li>Learn about specific use cases for GitHub Copilot Enterprise and hear how customers are enhancing their productivity.</li> <li>Review how to enable GitHub Copilot Enterprise.</li> </ul> <p><a href="https://learn.microsoft.com/en-us/training/modules/introduction-to-github-copilot-enterprise/">Go to Learning Module</a></p>', SYSDATETIME(), 10);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Introduction to GitHub Copilot for Business', N'<h3>Summary</h3> <p>Learn about the difference between GitHub Copilot Business versus GitHub Copilot Individuals. Also learn about specific use cases and customer stories for GitHub Copilot Business as well as how to enable it.</p> <h3>Learning Objectives</h3> <p>At the end of this module, you''ll be able to:</p> <ul> <li>Understand the difference between GitHub Copilot Business versus GitHub Copilot Individuals.</li> <li>Learn about specific use cases for GitHub Copilot Business and hear how customers are enhancing their productivity.</li> <li>Review how to enable GitHub Copilot Business.</li> </ul> <p><a href="https://learn.microsoft.com/en-us/training/modules/introduction-to-github-copilot-for-business/">Go to Learning Module</a></p>', SYSDATETIME(), 10);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Introduction to GitHub Copilot', N'<h3>Summary</h3> <p>GitHub Copilot uses OpenAI Codex to suggest code and entire functions in real time, right from your editor.</p> <h3>Learning Objectives</h3> <p>In this module, you will:</p> <ul> <li>Learn how GitHub Copilot can help you code by offering autocomplete-style suggestions.</li> <li>Learn about the various ways to trigger GitHub Copilot.</li> <li>Learn about the differences among GitHub Copilot Individual, Business, and Enterprise.</li> <li>Learn how to configure GitHub Copilot.</li> <li>Troubleshoot GitHub Copilot.</li> </ul> <p><a href="https://learn.microsoft.com/en-us/training/modules/introduction-to-github-copilot/">Go to Learning Module</a></p>', SYSDATETIME(), 10);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Introduction to Prompt Engineering with GitHub Copilot', N'<h3>Summary</h3> <p>Discover the essentials of creating effective prompts with GitHub Copilot. Uncover techniques to transform your coding comments into precise, actionable code, enhancing your development workflow.</p> <h3>Learning Objectives</h3> <p>By the end of this module, you''re able to:</p> <ul> <li>Craft effective prompts that optimize GitHub Copilot''s performance, ensuring precision and relevance in every code suggestion.</li> <li>Understand the intricate relationship between prompts and Copilot''s responses, and utilize best practices in prompt engineering.</li> <li>Gain insights into the underlying mechanism of how GitHub Copilot handles user prompts, from secure transmission to content filtering and context analysis.</li> </ul> <p><a href="https://learn.microsoft.com/en-us/training/modules/introduction-prompt-engineering-with-github-copilot/">Go to Learning Module</a></p>', SYSDATETIME(), 10);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Management and Customization Considerations with GitHub Copilot', N'<h3>Summary</h3> <p>In this module, we explore management and customization considerations with GitHub Copilot.</p> <h3>Learning Objectives</h3> <p>By the end of this module, you''ll:</p> <ul> <li>Understand the GitHub Copilot plans and their associated management and customization features.</li> <li>Gain insight into the contractual protections in GitHub Copilot and disabling matching public code.</li> <li>Know how to manage content exclusions.</li> <li>Recognize common problems with GitHub Copilot and their solutions.</li> </ul> <p><a href="https://learn.microsoft.com/en-us/training/modules/github-copilot-management-and-customizations/">Go to Learning Module</a></p>', SYSDATETIME(), 10);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Responsible AI with GitHub Copilot', N'<h3>Summary</h3> <p>This module explores the responsible use of AI in the context of GitHub Copilot, a generative AI tool for developers. It will equip you with the knowledge and skills to leverage Copilot effectively while mitigating potential ethical and operational risks associated with AI usage.</p> <h3>Learning Objectives</h3> <p>By the end of this module, students will be able to:</p> <ul> <li>Understand and apply the principles of Responsible AI usage.</li> <li>Identify limitations and mitigate risks associated with AI.</li> <li>Learn best practices for ensuring AI-generated code aligns with ethical standards and project-specific requirements.</li> <li>Recognize the importance of transparency and accountability in AI systems to build trust and maintain user confidence.</li> </ul> <p><a href="https://learn.microsoft.com/en-us/training/modules/responsible-ai-with-github-copilot/">Go to Learning Module</a></p>', SYSDATETIME(), 10);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Using Advanced GitHub Copilot Features', N'<h3>Summary</h3> <p>Use advanced GitHub Copilot features with a Python application.</p> <h3>Learning Objectives</h3> <p>By the end of this module, you''ll be able to:</p> <ul> <li>Apply slash commands to make code changes.</li> <li>Interact with GitHub Copilot using the Chat feature.</li> <li>Ask questions about your project using an agent.</li> </ul> <p><a href="https://learn.microsoft.com/en-us/training/modules/advanced-github-copilot/">Go to Learning Module</a></p>', SYSDATETIME(), 10);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Using GitHub Copilot with JavaScript', N'<h3>Summary</h3> <p>To work with JavaScript, take advantage of GitHub Copilot, an AI pair programmer that boosts productivity with autocomplete-style suggestions.</p> <h3>Learning Objectives</h3> <p>By the end of this module, you''re able to:</p> <ul> <li>Enable the GitHub Copilot extension in Visual Studio Code.</li> <li>Craft prompts that can generate useful suggestions from GitHub Copilot.</li> <li>Use GitHub Copilot to improve a JavaScript project.</li> </ul> <p><a href="https://learn.microsoft.com/en-us/training/modules/introduction-copilot-javascript/">Go to Learning Module</a></p>', SYSDATETIME(), 10);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Using GitHub Copilot with Python', N'<h3>Summary</h3> <p>GitHub Copilot is an AI pair programmer that offers autocomplete-style suggestions as you code in Python.</p> <h3>Learning Objectives</h3> <p>By the end of this module, you''re able to:</p> <ul> <li>Enable the GitHub Copilot extension in Visual Studio Code.</li> <li>Craft prompts that can generate useful suggestions from GitHub Copilot.</li> <li>Use GitHub Copilot to improve a Python project.</li> </ul> <p><a href="https://learn.microsoft.com/en-us/training/modules/introduction-copilot-python/">Go to Learning Module</a></p>', SYSDATETIME(), 10);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Agent driven repo clean up', N'<h3>Summary</h3> <p>In this exercise you will use <strong>GitHub Copilot Agent mode</strong> to automate a repository clean up. You will prompt the Agent to find dead code paths across the project and create a pull request that removes them. After reviewing the changes and running tests you will merge the pull request. Set aside twenty minutes.</p> <h3>What you will learn</h3> <ul> <li> <p>Prompting Copilot Agents for repository wide analysis.</p> </li> <li> <p>Letting the Agent generate a branch and pull request automatically.</p> </li> <li> <p>Reviewing deletions to confirm only dead code is removed.</p> </li> <li> <p>Running tests before merging automated clean-up changes.</p> </li> </ul> <h3>Before you start</h3> <p>Install the latest <strong>GitHub Copilot</strong> extension in VS Code and enable Agent mode under <strong>Settings &gt; GitHub Copilot &gt; Agents</strong>. Ensure your repository builds cleanly and that all tests pass with <code>npm test</code> <code>pytest</code> <code>dotnet test</code> or your framework''s command.</p> <h3>Steps</h3> <ul> <li> <p><strong>Step 1.</strong> Open the repository in VS Code and switch to the Copilot panel. Click <strong>Agent</strong> to enter Agent mode.</p> </li> <li> <p><strong>Step 2.</strong> In the Agent prompt type <code>Find dead code paths in this repo and open a PR deleting them</code> then press Enter.</p> </li> <li> <p><strong>Step 3.</strong> Wait while the Agent performs static analysis, creates a new branch for example <code>agent-dead-code-cleanup</code> and opens a pull request.</p> </li> <li> <p><strong>Step 4.</strong> Open the pull request in GitHub. Review the diff to ensure only unused code paths are removed and no critical logic is affected.</p> </li> <li> <p><strong>Step 5.</strong> Run your full test suite <code>npm test</code> <code>pytest</code> <code>dotnet test</code> or rely on continuous integration checks. Confirm all tests pass.</p> </li> <li> <p><strong>Step 6.</strong> If any test fails ask the Agent a follow-up prompt such as <code>Undo removal of misidentified function validateUser</code> apply the patch, then rerun tests.</p> </li> <li> <p><strong>Step 7.</strong> Once tests pass click <strong>Merge pull request</strong>. Delete the branch if prompted.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did the Agent open a pull request that deleted only dead code?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="agent-driven-repo-clean-up-q1" value="yes"> Yes</label><label><input type="radio" name="agent-driven-repo-clean-up-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did all tests pass after the clean up?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="agent-driven-repo-clean-up-q2" value="yes"> Yes</label><label><input type="radio" name="agent-driven-repo-clean-up-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Did you merge the pull request and delete the clean up branch?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="agent-driven-repo-clean-up-q3" value="yes"> Yes</label><label><input type="radio" name="agent-driven-repo-clean-up-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li> <p><a href="https://code.visualstudio.com/docs/copilot/chat/chat-agent-mode">Copilot Agents overview</a></p> </li> <li> <p><a href="https://docs.github.com/en/actions/using-workflows">Setting up tests in GitHub Actions</a></p> </li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Agent Hooks', N'<h3>Summary</h3> <p>In this exercise you will create <strong>agent hooks</strong> — small shell scripts that run automatically at specific points during a GitHub Copilot agent session. You will build four hooks that cover real-world scenarios: blocking hardcoded secrets, auto-running tests, injecting project context, and logging prompts. Expect to spend thirty to forty-five minutes.</p> <h3>What you will learn</h3> <ul> <li>Understanding the eight agent lifecycle events available for hooks.</li> <li>Creating hook configuration files in <code>.github/hooks/</code>.</li> <li>Writing a <code>PreToolUse</code> hook that scans for hardcoded secrets and blocks the write if any are found.</li> <li>Writing a <code>PostToolUse</code> hook that automatically runs unit tests whenever the agent modifies a source file.</li> <li>Using a <code>SessionStart</code> hook to inject project context from a <code>CONTEXT.md</code> file into every agent session.</li> <li>Using the <code>/create-hook</code> slash command to generate a <code>UserPromptSubmit</code> hook that logs every agent prompt to a local file.</li> </ul> <h3>Before you start</h3> <ul> <li>Ensure VS Code has the latest GitHub Copilot Chat extension installed and <strong>agent mode is enabled</strong>.</li> <li>You need a terminal (bash or zsh on Mac/Linux, or Git Bash on Windows).</li> <li>No prior shell scripting experience is required — all script content is provided in the steps below.</li> </ul> <h3>Steps</h3> <hr /> <h4>🔐 Hook 1 — Block hardcoded secrets (PreToolUse)</h4> <ul> <li><strong>Step 1.</strong> Open your terminal and navigate to the root of your repository. Run the following command to create the hooks folder:</li> </ul> <p><code>bash mkdir -p .github/hooks</code></p> <ul> <li><strong>Step 2.</strong> Create the hook configuration file by running this command in your terminal:</li> </ul> <p><code>bash cat &gt; .github/hooks/secret-scanner.json &lt;&lt; ''EOF'' { "hooks": { "PreToolUse": [ { "type": "command", "command": "bash .github/hooks/secret-scanner.sh" } ] } } EOF</code></p> <ul> <li><strong>Step 3.</strong> Create the shell script that does the actual scanning by running this command in your terminal:</li> </ul> <p>```bash<br /> cat &gt; .github/hooks/secret-scanner.sh &lt;&lt; ''EOF''<br /> #!/bin/bash<br /> # Read the hook input from stdin (VS Code sends JSON containing tool_input)<br /> content=$(cat)</p> <p># Check for common secret patterns in the tool input<br /> if echo "$content" | grep -qE ''ghp_[A-Za-z0-9]+|AKIA[0-9A-Z]{16}|sk-[A-Za-z0-9]+|password\s<em>=\s</em>\S+''; then<br /> echo "❌ SECRET DETECTED: Hardcoded secret pattern found. Blocking write." &gt;&amp;2<br /> # Output deny decision as JSON — VS Code reads this on exit 0<br /> echo ''{"hookSpecificOutput":{"permissionDecision":"deny","permissionDecisionReason":"Blocked: hardcoded secret pattern detected (e.g. GitHub token, AWS key, or password)."}}''<br /> exit 0<br /> fi</p> <p>exit 0<br /> EOF<br /> chmod +x .github/hooks/secret-scanner.sh<br /> ```</p> <blockquote> <p><strong>How it works:</strong> When a <code>PreToolUse</code> hook outputs JSON with <code>"permissionDecision": "deny"</code> to <strong>stdout</strong> and exits with code <code>0</code>, VS Code prevents the agent from executing that tool call. The human-readable message is sent to <strong>stderr</strong> (using <code>&gt;&amp;2</code>) so it appears in the Hooks output channel without interfering with the JSON protocol. Exit code <code>1</code> only shows a non-blocking warning and does <strong>not</strong> block the action.</p> </blockquote> <ul> <li><strong>Step 4.</strong> Open VS Code, switch to <strong>Agent mode</strong> in the Copilot Chat panel, and send this exact prompt:</li> </ul> <blockquote> <p>Create a file called <code>test-credentials.txt</code> with the following content: <code>token=ghp_fakeABCDEFGH1234567890</code></p> </blockquote> <p>✅ <strong>Expected result:</strong> Copilot reports the write was blocked and the file is NOT created in your repository.</p> <hr /> <h4>🧪 Hook 2 — Auto-run tests after edits (PostToolUse)</h4> <ul> <li><strong>Step 5.</strong> Create the hook configuration file by running this command in your terminal:</li> </ul> <p><code>bash cat &gt; .github/hooks/test-runner.json &lt;&lt; ''EOF'' { "hooks": { "PostToolUse": [ { "type": "command", "command": "bash .github/hooks/test-runner.sh" } ] } } EOF</code></p> <ul> <li><strong>Step 6.</strong> Create the shell script by running this command in your terminal:</li> </ul> <p>```bash<br /> cat &gt; .github/hooks/test-runner.sh &lt;&lt; ''EOF''<br /> #!/bin/bash<br /> # VS Code sets TOOL_INPUT_FILE_PATH to the path of the modified file<br /> MODIFIED_FILE="${TOOL_INPUT_FILE_PATH:-}"</p> <p>if [[ -z "$MODIFIED_FILE" ]]; then<br /> echo "ℹ️ No file path provided. Skipping." &gt;&amp;2<br /> exit 0<br /> fi</p> <p>if [[ "$MODIFIED_FILE" == <em>.js || "$MODIFIED_FILE" == </em>.ts ]]; then<br /> echo "🧪 Running JavaScript/TypeScript tests..." &gt;&amp;2<br /> npm test &gt;&amp;2<br /> elif [[ "$MODIFIED_FILE" == *.py ]]; then<br /> echo "🧪 Running Python tests..." &gt;&amp;2<br /> pytest &gt;&amp;2<br /> else<br /> echo "ℹ️ No test runner configured for this file type. Skipping." &gt;&amp;2<br /> exit 0<br /> fi<br /> EOF<br /> chmod +x .github/hooks/test-runner.sh<br /> ```</p> <blockquote> <p><strong>How it works:</strong> VS Code sets the <code>TOOL_INPUT_FILE_PATH</code> environment variable to the path of the file being modified. Hook scripts read this variable — command-line arguments are <strong>not</strong> passed to hooks. All diagnostic output uses <code>&gt;&amp;2</code> (stderr) so it appears in the Hooks output channel without interfering with VS Code''s JSON protocol on stdout.</p> </blockquote> <ul> <li><strong>Step 7.</strong> In Agent mode, send this exact prompt:</li> </ul> <blockquote> <p>Add a comment to the top of any existing <code>.js</code>, <code>.ts</code>, or <code>.py</code> file in this project saying <code># Updated by agent</code>.</p> </blockquote> <p>✅ <strong>Expected result:</strong> After the agent edits the file, you see test output appear automatically in the terminal.</p> <hr /> <h4>🧠 Hook 3 — Inject project context at session start (SessionStart)</h4> <ul> <li><strong>Step 8.</strong> Create a <code>CONTEXT.md</code> file in the root of your repository by running this command in your terminal:</li> </ul> <p>```bash<br /> cat &gt; CONTEXT.md &lt;&lt; ''EOF''<br /> # Project Context</p> <p>## Current Sprint Goal<br /> Improve test coverage to 80% and fix all critical security linting issues.</p> <p>## Architecture<br /> This is a Node.js REST API using Express. All routes live in <code>/src/routes</code>. Database models are in <code>/src/models</code>.</p> <p>## Coding Standards<br /> - Use <code>async/await</code> instead of callbacks.<br /> - All functions must have JSDoc comments.<br /> - Never hardcode secrets — use environment variables via <code>process.env</code>.<br /> EOF<br /> ```</p> <ul> <li><strong>Step 9.</strong> Create the hook configuration file by running this command in your terminal:</li> </ul> <p><code>bash cat &gt; .github/hooks/context-injector.json &lt;&lt; ''EOF'' { "hooks": { "SessionStart": [ { "type": "command", "command": "bash .github/hooks/context-injector.sh" } ] } } EOF</code></p> <ul> <li><strong>Step 10.</strong> Create the shell script by running this command in your terminal:</li> </ul> <p>```bash<br /> cat &gt; .github/hooks/context-injector.sh &lt;&lt; ''EOF''<br /> #!/bin/bash<br /> CONTEXT_FILE="CONTEXT.md"</p> <p>if [ -f "$CONTEXT_FILE" ]; then<br /> echo "📋 Injecting project context from $CONTEXT_FILE..." &gt;&amp;2<br /> cat "$CONTEXT_FILE" &gt;&amp;2<br /> else<br /> echo "⚠️ No CONTEXT.md found. Skipping context injection." &gt;&amp;2<br /> fi<br /> EOF<br /> chmod +x .github/hooks/context-injector.sh<br /> ```</p> <ul> <li><strong>Step 11.</strong> Start a <strong>new agent session</strong> in the Copilot Chat panel. Then send this exact prompt:</li> </ul> <blockquote> <p>What are the coding standards for this project?</p> </blockquote> <p>✅ <strong>Expected result:</strong> Copilot answers using the content from your <code>CONTEXT.md</code> file without you having to paste it manually.</p> <hr /> <h4>📋 Hook 4 — Log all prompts (UserPromptSubmit)</h4> <ul> <li><strong>Step 12.</strong> In the Copilot Chat panel (in Agent mode), type the following slash command:</li> </ul> <blockquote> <p><code>/create-hook</code></p> </blockquote> <p>When Copilot asks you to describe the hook, enter this:</p> <blockquote> <p>A <code>UserPromptSubmit</code> hook that appends every prompt I send to the agent — along with the current date and time — to a file called <code>agent-prompt-log.txt</code> in the repository root.</p> </blockquote> <ul> <li> <p><strong>Step 13.</strong> Copilot will generate the hook JSON and shell script for you. Save both files into <code>.github/hooks/</code> exactly as Copilot instructs.</p> </li> <li> <p><strong>Step 14.</strong> Send a few test prompts to the agent in Agent mode (for example: <code>What files are in this repo?</code>). Then open <code>agent-prompt-log.txt</code> in the VS Code file explorer (it will be in the root of your repository).</p> </li> </ul> <p>✅ <strong>Expected result:</strong> Each prompt you sent appears as a timestamped line in <code>agent-prompt-log.txt</code>, for example:<br /> <code>[2026-03-09 10:32:01] What files are in this repo?</code></p> <hr /> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did the PreToolUse secret scanner hook block the write of <code>test-credentials.txt</code> containing <code>ghp_fakeABCDEFGH1234567890</code>?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="agent-hooks-q1" value="yes"> Yes</label><label><input type="radio" name="agent-hooks-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did the PostToolUse hook automatically run tests in the terminal after the agent edited a source file?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="agent-hooks-q2" value="yes"> Yes</label><label><input type="radio" name="agent-hooks-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Did the SessionStart hook inject context from <code>CONTEXT.md</code> when you asked about coding standards?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="agent-hooks-q3" value="yes"> Yes</label><label><input type="radio" name="agent-hooks-q3" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="4"> <li>Were you able to create a <code>UserPromptSubmit</code> logging hook using <code>/create-hook</code> and verify timestamped entries in <code>agent-prompt-log.txt</code>?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="agent-hooks-q4" value="yes"> Yes</label><label><input type="radio" name="agent-hooks-q4" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li> <p><a href="https://code.visualstudio.com/docs/copilot/customization/hooks">Agent hooks in VS Code</a></p> </li> <li> <p><a href="https://code.visualstudio.com/docs/copilot/agents/agent-tools">Agent tools and approval</a></p> </li> <li> <p><a href="https://code.visualstudio.com/docs/copilot/customization/custom-instructions">Custom instructions in VS Code</a></p> </li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Agent Skills', N'<h3>Summary</h3> <p>In this exercise you will create a custom <strong>agent skill</strong> by writing a <code>SKILL.md</code> file that teaches GitHub Copilot domain-specific knowledge. Skills let Copilot automatically discover and apply your team''s practices without you writing explicit prompts every time. Expect to spend twenty to thirty minutes.</p> <h3>What you will learn</h3> <ul> <li>Understanding the SKILL.md format with YAML front matter and instructions body.</li> <li>Creating a skill that Copilot automatically invokes when relevant.</li> <li>Using the <code>/create-skill</code> slash command to generate a skill with AI assistance.</li> <li>Organizing skills at the repository, user, and workspace levels.</li> </ul> <h3>Before you start</h3> <p>Ensure you have VS Code with the latest GitHub Copilot Chat extension. Agent mode must be enabled (<code>chat.agent.enabled</code>). Have a repository where you can add files to the <code>.github/skills/</code> directory.</p> <h3>Steps</h3> <ul> <li> <p><strong>Step 1.</strong> Create the folder <code>.github/skills/</code> in your repository if it does not already exist.</p> </li> <li> <p><strong>Step 2.</strong> Create a file called <code>.github/skills/code-review/SKILL.md</code> with the following structure: YAML front matter containing <code>name</code> and <code>description</code> fields, followed by a body with instructions for performing code reviews according to your team''s standards. For example, instruct Copilot to check for error handling, verify input validation, and flag any hardcoded secrets.</p> </li> <li> <p><strong>Step 3.</strong> Open Copilot Chat in Agent mode. Enter a prompt that would naturally trigger the skill, such as: <code>Review the changes in src/auth/login.ts for any issues.</code></p> </li> <li> <p><strong>Step 4.</strong> Observe that Copilot reads and applies your skill instructions automatically. The skill name should appear in the chat response or tool call log showing it was activated.</p> </li> <li> <p><strong>Step 5.</strong> Now use the AI-assisted approach. Type <code>/create-skill</code> in Copilot Chat and follow the prompts to generate a new skill for a different domain, such as database migration best practices.</p> </li> <li> <p><strong>Step 6.</strong> Optionally create a user-level skill by placing a <code>SKILL.md</code> file under <code>~/.copilot/skills/my-skill/SKILL.md</code>. This skill will be available across all your repositories.</p> </li> <li> <p><strong>Step 7.</strong> Test that both skills activate correctly by entering prompts that match each skill''s description.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did Copilot automatically discover and apply the SKILL.md instructions during a relevant prompt?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="agent-skills-q1" value="yes"> Yes</label><label><input type="radio" name="agent-skills-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did the /create-skill command successfully generate a new skill file?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="agent-skills-q2" value="yes"> Yes</label><label><input type="radio" name="agent-skills-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Were you able to organize skills at the repository or user level and verify they activated?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="agent-skills-q3" value="yes"> Yes</label><label><input type="radio" name="agent-skills-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li> <p><a href="https://code.visualstudio.com/docs/copilot/customization/agent-skills">Agent skills in VS Code</a></p> </li> <li> <p><a href="https://agentskills.io">Agent Skills open standard</a></p> </li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Automated PR review rules', N'<h3>Summary</h3> <p>In this challenge, you’ll enable GitHub Copilot’s <strong>Review changes</strong> feature to provide AI-generated suggestions on your pull requests. After configuring your repository to use Copilot for reviews, you’ll open a pull request and see Copilot’s inline review comments in action. This activity takes about fifteen minutes. Note that some of the features in this challenge requires <strong>GitHub Enterprise.</strong></p> <h3>What you will learn</h3> <ul> <li> <p>How to enable GitHub Copilot’s review features for pull requests.</p> </li> <li> <p>How to interpret Copilot-generated feedback and suggestions.</p> </li> <li> <p>How to act on Copilot’s comments by updating your code or replying in threads.</p> </li> <li> <p>How to complete the review and merge process with both AI and human approvals.</p> </li> </ul> <h3>Before you start</h3> <p>You need <strong>GitHub Copilot</strong> access and appropriate permissions to open pull requests in the target repository. Ensure that GitHub Copilot is enabled for your account and the repository. The <strong>Review changes</strong> feature uses premium Copilot requests.</p> <h3>Steps</h3> <ul> <li> <p><strong>Step 1.</strong> In the browser, open the repository and create a new branch using <code>git checkout -b copilot-review-test</code>. Make a small change in the code.</p> </li> <li> <p><strong>Step 2.</strong> Push the branch to GitHub and open a pull request as usual.</p> </li> <li> <p><strong>Step 3.</strong> In the pull request view, click the <strong>Copilot</strong> button and select <strong>Review changes</strong>.</p> </li> <li> <p><strong>Step 4.</strong> Wait for Copilot to generate its review. Copilot will leave inline comments with suggested improvements, bug fixes, or explanations.</p> </li> <li> <p><strong>Step 5.</strong> Respond to at least one comment by either updating your code or replying directly in the conversation.</p> </li> <li> <p><strong>Step 6.</strong> Request a human review if needed, then complete the merge once both AI and human reviewers (if required) have approved.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did you successfully initiate a Copilot review on a pull request?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="automated-pr-review-rules-q1" value="yes"> Yes</label><label><input type="radio" name="automated-pr-review-rules-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did Copilot leave any inline comments or suggestions?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="automated-pr-review-rules-q2" value="yes"> Yes</label><label><input type="radio" name="automated-pr-review-rules-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Did you respond to at least one suggestion and merge the pull request?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="automated-pr-review-rules-q3" value="yes"> Yes</label><label><input type="radio" name="automated-pr-review-rules-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li> <p><a href="https://docs.github.com/en/copilot/using-github-copilot/code-review/using-copilot-code-review">Using Copilot for code review</a></p> </li> <li> <p><a href="https://docs.github.com/en/pull-requests">Working with pull requests</a></p> </li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'CLI : Explain a scary command', N'<h3>Summary</h3> <p>In this exercise you will use <strong>GitHub Copilot CLI</strong> to understand a complex shell command from your own project. You will ask Copilot to explain the command <code>git diff --name-only | head -n 1</code> through the <code>gh copilot explain</code> feature. Plan for about ten to fifteen minutes.</p> <h3>What you will learn</h3> <ul> <li> <p>Installing and using the <code>gh copilot</code> extension.</p> </li> <li> <p>Running <code>gh copilot explain</code> on a shell command in your terminal.</p> </li> <li> <p>Reading Copilot output to confirm understanding of each command part.</p> </li> <li> <p>Applying the same method to any unfamiliar command in future.</p> </li> </ul> <h3>Prerequisites</h3> <p>Confirm that the GitHub CLI is installed by running <code>gh --version</code>. Install the Copilot extension with <code>gh extension install github/gh-copilot</code> if it is not yet present. Authenticate with <code>gh auth login</code> and stay in the root folder of a repository you can modify.</p> <h3>Steps</h3> <ul> <li> <p><strong>Step 1.</strong> Open a terminal in the root folder of your project.</p> </li> <li> <p><strong>Step 2.</strong> Copy and paste the command below then press Enter.</p> </li> </ul> <p><code>gh copilot explain "$(git diff --name-only | head -n 1)"</code></p> <ul> <li> <p><strong>Step 3.</strong> Wait for Copilot to produce a line by line explanation of the pipeline.</p> </li> <li> <p><strong>Step 4.</strong> Compare each part of the explanation with your own understanding. If something is not clear ask a follow up question such as <code>gh copilot explain "head -n 1"</code>.</p> </li> <li> <p><strong>Step 5.</strong> Run the original command without the Copilot prefix and view the output so you can link explanation to real data.</p> </li> <li> <p><strong>Step 6.</strong> Use <code>gh copilot explain</code> on a different command from your shell history to reinforce the technique.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did Copilot return an explanation that listed every flag and sub command?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="cli-explain-a-scary-command-q1" value="yes"> Yes</label><label><input type="radio" name="cli-explain-a-scary-command-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did you confirm the explanation by running the original command yourself?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="cli-explain-a-scary-command-q2" value="yes"> Yes</label><label><input type="radio" name="cli-explain-a-scary-command-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Did you try <code>gh copilot explain</code> on at least one more command from your project?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="cli-explain-a-scary-command-q3" value="yes"> Yes</label><label><input type="radio" name="cli-explain-a-scary-command-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li> <p><a href="https://githubnext.com/projects/copilot-cli">GitHub Copilot CLI project page</a></p> </li> <li> <p><a href="https://docs.github.com/en/copilot/using-github-copilot/using-github-copilot-in-the-command-line">gh copilot command reference</a></p> </li> <li> <p><a href="https://docs.github.com/en/copilot/getting-started-with-github-copilot">Getting started with GitHub Copilot</a></p> </li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'CLI suggest & execute', N'<h3>Summary</h3> <p>In this exercise you will use <strong>GitHub Copilot CLI</strong> to suggest and run a command that cleans up local branches already merged into main. You will review the agent''s plan, approve the command, then verify the result with <code>git branch</code>. The task should take about ten minutes.</p> <h3>What you will learn</h3> <ul> <li> <p>Launching the <code>copilot</code> CLI interactive agent to request shell commands.</p> </li> <li> <p>Reviewing and approving the agent''s suggested command before execution.</p> </li> <li> <p>Verifying local branch cleanup with <code>git branch</code>.</p> </li> <li> <p>Using Copilot CLI for other repository maintenance tasks.</p> </li> </ul> <h3>Prerequisites</h3> <p>Confirm that the Copilot CLI is installed with <code>copilot --version</code>. Authenticate with <code>copilot login</code> and open a terminal in the root of a repository that has multiple merged branches.</p> <h3>Steps</h3> <ul> <li><strong>Step 1.</strong> In the project root launch the interactive Copilot CLI agent.</li> </ul> <p><code>copilot</code></p> <ul> <li> <p><strong>Step 2.</strong> In the interactive session type: <code>Delete all local branches that have already been merged into main</code>. The agent will propose a shell command — it should resemble <code>git branch --merged | grep -v "main" | xargs -n 1 git branch -d</code>.</p> </li> <li> <p><strong>Step 3.</strong> When the agent asks for permission to execute the command, review it and approve. If the agent asks clarifying questions, confirm you want to clean up merged branches.</p> </li> <li> <p><strong>Step 4.</strong> After execution run <code>git branch</code> to list local branches and confirm that only active branches remain.</p> </li> <li> <p><strong>Step 5.</strong> Explore other cleanup ideas by typing <code>List the largest files in this repo</code> or a task of your choice. Exit the CLI with <code>/exit</code> when done.</p> </li> <li> <p><strong>Step 6.</strong> Commit any auxiliary changes if applicable and push to remote.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did Copilot suggest a safe branch cleanup command?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="cli-suggest-execute-q1" value="yes"> Yes</label><label><input type="radio" name="cli-suggest-execute-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did the command remove local branches that are already merged?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="cli-suggest-execute-q2" value="yes"> Yes</label><label><input type="radio" name="cli-suggest-execute-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Did you confirm the result with <code>git branch</code>?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="cli-suggest-execute-q3" value="yes"> Yes</label><label><input type="radio" name="cli-suggest-execute-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li><a href="https://docs.github.com/en/copilot/github-copilot-in-the-cli/about-github-copilot-in-the-cli">GitHub Copilot in the CLI</a></li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Cloud Agent', N'<h3>Summary</h3> <p>In this exercise you will use the <strong>GitHub Copilot coding agent</strong> (cloud agent) to perform a non-trivial code change entirely in the cloud. The cloud agent creates a remote session, implements changes autonomously, and opens a pull request for your review. Expect to spend twenty to thirty minutes.</p> <h3>What you will learn</h3> <ul> <li>Starting a cloud agent session from VS Code or GitHub.com.</li> <li>Providing a well-structured prompt that the cloud agent can execute autonomously.</li> <li>Monitoring the cloud agent progress and reviewing its generated pull request.</li> <li>Handing off a local Plan session to the cloud agent for execution.</li> </ul> <h3>Before you start</h3> <p>Ensure your GitHub organization has <strong>Copilot coding agent</strong> (Cloud Agent) enabled. You need write access to a repository hosted on GitHub. Have the latest VS Code with the GitHub Copilot Chat extension installed.</p> <h3>Steps</h3> <ul> <li> <p><strong>Step 1.</strong> Open a new Copilot Chat Session in VS Code and select <strong>Cloud</strong> from the session type dropdown at the bottom of the chat panel.</p> </li> <li> <p><strong>Step 2.</strong> Enter a refactoring prompt that affects multiple files, for example: <code>Refactor the logging module to use structured logging with JSON output across all services.</code></p> </li> <li> <p><strong>Step 3.</strong> The cloud agent provisions a remote environment. Watch the status bar for progress. You can continue working locally while it runs.</p> </li> <li> <p><strong>Step 4.</strong> When the cloud agent finishes, it posts a notification with a link to a new pull request. Open the pull request on GitHub.</p> </li> <li> <p><strong>Step 5.</strong> Review the diff, inspect the commit messages the agent wrote, and verify tests pass in CI.</p> </li> <li> <p><strong>Step 6.</strong> Alternatively, start a <strong>Plan</strong> session locally by switching to Plan mode. After the plan is generated, switch to the cloud agent using the Session dropdown option and select <strong>continue in Cloud</strong>. Ask the agent to implement the changes and let the Copilot Coding agent execute the plan remotely.</p> </li> <li> <p><strong>Step 7.</strong> Merge the pull request once you are satisfied with the changes.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did the Cloud agent successfully create a remote session and begin working on your prompt?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="cloud-agent-q1" value="yes"> Yes</label><label><input type="radio" name="cloud-agent-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did the cloud agent open a pull request with the implemented changes?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="cloud-agent-q2" value="yes"> Yes</label><label><input type="radio" name="cloud-agent-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Were you able to review the diff and verify the changes before merging?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="cloud-agent-q3" value="yes"> Yes</label><label><input type="radio" name="cloud-agent-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li> <p><a href="https://code.visualstudio.com/docs/copilot/agents/cloud-agents">Cloud agents in VS Code</a></p> </li> <li> <p><a href="https://docs.github.com/en/enterprise-cloud@latest/copilot/concepts/agents/coding-agent/about-coding-agent">Copilot coding agent on GitHub</a></p> </li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Commit message concierge', N'<h3>Summary</h3> <p>This exercise shows how to let <strong>GitHub Copilot</strong> write commit messages for you. You will stage today’s changes invoke Copilot’s commit message helper accept the draft then amend it with extra context if required. The task should take ten to fifteen minutes.</p> <h3>What you will learn</h3> <ul> <li> <p>Staging file changes with <code>git add</code> or your IDE source control panel.</p> </li> <li> <p>Triggering Copilot to draft a commit message from the staged diff.</p> </li> <li> <p>Editing the AI generated message to add project specific context.</p> </li> <li> <p>Committing and pushing the change to your remote repository.</p> </li> </ul> <h3>Prerequisites</h3> <p>Confirm that GitHub Copilot is enabled in <strong>your IDE</strong> for example VS Code JetBrains or Visual Studio. Make sure you have several modified files ready to commit in your repository.</p> <h3>Steps</h3> <ul> <li> <p><strong>Step 1.</strong> Stage all changes by running <code>git add -A</code> in the terminal or selecting files in the IDE source control view.</p> </li> <li> <p><strong>Step 2.</strong> Start the commit process.</p> </li> <li> <p>In VS Code place the cursor in the commit message box.</p> </li> <li> <p>In JetBrains open the Commit tool window.</p> </li> <li> <p><strong>Step 3.</strong> Wait a moment. Copilot detects the staged diff and inserts a suggested message.</p> </li> <li> <p><strong>Step 4.</strong> Read the draft. Use the keyboard to append extra context such as ticket numbers or motivations.</p> </li> <li> <p><strong>Step 5.</strong> Save the commit.</p> </li> <li> <p>In the terminal type <code>git commit</code> then accept the message.</p> </li> <li> <p>In the IDE click Commit or press the shortcut.</p> </li> <li> <p><strong>Step 6.</strong> Push the commit to your remote with <code>git push</code> or the IDE push command.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did Copilot generate a commit message automatically from your staged changes?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="commit-message-concierge-q1" value="yes"> Yes</label><label><input type="radio" name="commit-message-concierge-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did you add additional detail such as a ticket reference or rationale?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="commit-message-concierge-q2" value="yes"> Yes</label><label><input type="radio" name="commit-message-concierge-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Did the commit push successfully to the remote repository?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="commit-message-concierge-q3" value="yes"> Yes</label><label><input type="radio" name="commit-message-concierge-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li><a href="https://docs.github.com/en/copilot/getting-started-with-github-copilot#generate-commit-messages">Generating commit messages with Copilot</a></li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Context augmented agent', N'<h3>Summary</h3> <p>In this advanced workflow, you''ll configure a <strong>GitHub Copilot Space</strong> to centralize your project context so that Copilot can reference your organization''s internal documentation and code. You''ll then ask Copilot to draft an ADR proposing a migration from a monolith to microservices. This task takes about thirty minutes.</p> <h3>What you will learn</h3> <ul> <li> <p>Creating and configuring a GitHub Copilot Space.</p> </li> <li> <p>Adding code, documents, and custom instructions to a Space.</p> </li> <li> <p>Sharing a Space across your organization to scale expertise.</p> </li> <li> <p>Prompting Copilot in a Space to draft an ADR using contextual knowledge.</p> </li> </ul> <h3>Before you start</h3> <p>Copilot Spaces are available to all GitHub Copilot users, including Copilot Free, at <a href="https://github.com/copilot/spaces">github.com/copilot/spaces</a>. Prepare your documentation (Markdown, text, or supported formats) and ensure it is stored in a GitHub repository so it can be attached directly to the Space.</p> <h3>Steps</h3> <ul> <li> <p><strong>Step 1.</strong> Navigate to <a href="https://github.com/copilot/spaces">github.com/copilot/spaces</a> and click <strong>New space</strong>. If creating a shared space for your organization, select your organization as the owner.</p> </li> <li> <p><strong>Step 2.</strong> Give your Space a name (e.g., <code>Architecture Docs</code>) and add context sources. Click <strong>Add context</strong>, then select <strong>Repository</strong> to attach your architecture documentation repository directly from GitHub.</p> </li> <li> <p><strong>Step 3.</strong> Add any additional files, notes, or specs relevant to your system''s design by clicking <strong>Add context</strong> and choosing the appropriate source type.</p> </li> <li> <p><strong>Step 4.</strong> Optionally, define <strong>Custom instructions</strong> within the Space to further tailor Copilot''s responses — for example, specifying the ADR format your team follows.</p> </li> <li> <p><strong>Step 5.</strong> Create a new branch with <code>git checkout -b adr-microservices</code>. Then open the Space chat and type:<br /> <code>Draft an Architecture Decision Record for migrating our monolith to microservices using our current architecture documents as context.</code></p> </li> <li> <p><strong>Step 6.</strong> Review the generated ADR, which should include: <em>Context</em>, <em>Decision</em>, <em>Status</em>, and <em>Consequences</em>.</p> </li> <li> <p><strong>Step 7.</strong> Save the draft to <code>docs/adr/0005-microservices-migration.md</code>, make any organization-specific edits, commit the file, and push the branch for review.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did you successfully create a Copilot Space and add your documentation as context?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="context-augmented-agent-q1" value="yes"> Yes</label><label><input type="radio" name="context-augmented-agent-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did Copilot cite information from your documentation in the ADR draft?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="context-augmented-agent-q2" value="yes"> Yes</label><label><input type="radio" name="context-augmented-agent-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Did you commit and push the ADR for review?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="context-augmented-agent-q3" value="yes"> Yes</label><label><input type="radio" name="context-augmented-agent-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li> <p><a href="https://docs.github.com/en/copilot/concepts/context/spaces">Copilot Spaces</a></p> </li> <li> <p><a href="https://adr.github.io/madr/">Markdown ADR template</a></p> </li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Copilot for SQL', N'<h3>Summary</h3> <p>In this activity you will let <strong>GitHub Copilot</strong> write SQL for you by adding a plain English comment to a data access file. Copilot will turn the comment <code>-- top 10 customers by spend last year</code> into a full query. You will run the query against your database and review the results. Allocate about fifteen minutes.</p> <h3>What you will learn</h3> <ul> <li> <p>Prompting Copilot with natural language in SQL files.</p> </li> <li> <p>Accepting inline SQL suggestions with the keyboard.</p> </li> <li> <p>Executing generated queries in your database client.</p> </li> <li> <p>Validating query accuracy against sample data.</p> </li> </ul> <h3>Before you start</h3> <p>Confirm Copilot is active in <strong>your IDE</strong> such as VS Code or JetBrains. Ensure you have a database connection configured and working query runner for example psql mysql cli or the built in database panel.</p> <h3>Steps</h3> <ul> <li> <p><strong>Step 1.</strong> Open the file in your data layer where SQL queries are stored for example <code>customerQueries.sql</code> or a repository migration file.</p> </li> <li> <p><strong>Step 2.</strong> On a new line type the comment <code>-- top 10 customers by spend last year</code> and press Enter.</p> </li> <li> <p><strong>Step 3.</strong> Pause. Copilot shows a complete SQL query suggestion. Press <strong>Tab</strong> to accept or use <strong>Alt ]</strong> or <strong>Option ]</strong> to view other versions.</p> </li> <li> <p><strong>Step 4.</strong> Save the file then copy the generated query or run it directly in your database client connected to the correct schema.</p> </li> <li> <p><strong>Step 5.</strong> Verify that the query returns ten rows ordered by spend for the previous calendar year. Adjust date filters if required then rerun.</p> </li> <li> <p><strong>Step 6.</strong> Commit the new query file or update with a descriptive message possibly drafted by Copilot.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did Copilot produce a syntactically correct SQL query?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="copilot-for-sql-q1" value="yes"> Yes</label><label><input type="radio" name="copilot-for-sql-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did the query return the expected ten rows sorted by spend?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="copilot-for-sql-q2" value="yes"> Yes</label><label><input type="radio" name="copilot-for-sql-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Did you commit the query or save it in the data layer?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="copilot-for-sql-q3" value="yes"> Yes</label><label><input type="radio" name="copilot-for-sql-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li> <p><a href="https://dev.to/karenpayneoregon/github-copilot-generate-sql-pd3">Generating SQL with GitHub Copilot</a></p> </li> <li> <p><a href="https://techcommunity.microsoft.com/blog/azuresqlblog/unleashing-sql-sorcery-increasing-performance-and-complexity-with-github-copilot/3898909">Unleashing SQL Sorcery with GitHub Copilot</a></p> </li> <li> <p><a href="https://docs.github.com/en/copilot/using-github-copilot/best-practices-for-using-github-copilot">Best Practices for Using GitHub Copilot</a></p> </li> <li> <p><a href="https://techcommunity.microsoft.com/blog/azuresqlblog/github-copilot-for-sql-developers-turbocharge-your-sql-development-workflow/3875915">Turbocharge Your SQL Development Workflow</a></p> </li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Copilot-instructions.md power-up', N'<h3>Summary</h3> <p>In this personalization exercise you will add a <code>copilot-instructions.md</code> file to your repository root (or use the VS Code Personalize panel) and write three sentences that describe your preferred coding style, frameworks, and docstring format. After saving the file you will ask GitHub Copilot to draft a helper utility and observe how it follows your new instructions. The task should take about fifteen minutes.</p> <h3>What you will learn</h3> <ul> <li> <p>Creating or editing <code>copilot-instructions.md</code> to guide Copilot output.</p> </li> <li> <p>Using the Personalize panel in VS Code to manage Copilot instructions.</p> </li> <li> <p>Requesting Copilot to generate code that follows custom guidelines.</p> </li> <li> <p>Committing repository level instructions for team visibility.</p> </li> </ul> <h3>Before you start</h3> <p>Ensure GitHub Copilot is enabled in <strong>your IDE</strong> such as VS Code JetBrains or Visual Studio. Have at least one branch where you can commit the new file without affecting production code.</p> <h3>Steps</h3> <ul> <li> <p><strong>Step 1.</strong> Create and check out a branch named <code>copilot-instructions</code> using <code>git checkout -b copilot-instructions</code> or the source control panel.</p> </li> <li> <p><strong>Step 2.</strong> Create a new file <code>.github/copilot-instructions.md</code> in the repository root.</p> </li> <li> <p><strong>Step 3.</strong> Add exactly three sentences that describe:</p> </li> <li> <p>Your preferred indentation and naming style.</p> </li> <li> <p>Your main framework or library choices.</p> </li> <li> <p>Your docstring or comment format.</p> </li> </ul> <p>Example: <code>I use four space indentation and snake_case for functions. All helpers target FastAPI. Docstrings must follow the Google style guide.</code></p> <ul> <li> <p><strong>Step 4.</strong> Save the file or panel and close it.</p> </li> <li> <p><strong>Step 5.</strong> Open any source file and prompt Copilot Chat with <code>Draft a helper utility to validate email addresses</code>. Accept the suggestion.</p> </li> <li> <p><strong>Step 6.</strong> Confirm that the generated code matches your stated style, framework import, and docstring format.</p> </li> <li> <p><strong>Step 7.</strong> Stage and commit <code>.github/copilot-instructions.md</code> with a clear message then push the branch and open a pull request.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did you add three clear sentences to <code>copilot-instructions.md</code>?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="copilot-instructionsmd-power-up-q1" value="yes"> Yes</label><label><input type="radio" name="copilot-instructionsmd-power-up-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did Copilot generate a helper utility that follows your specified style?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="copilot-instructionsmd-power-up-q2" value="yes"> Yes</label><label><input type="radio" name="copilot-instructionsmd-power-up-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Did you commit the new instruction file to the repository?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="copilot-instructionsmd-power-up-q3" value="yes"> Yes</label><label><input type="radio" name="copilot-instructionsmd-power-up-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li> <p><a href="https://docs.github.com/en/copilot/customizing-copilot/adding-repository-custom-instructions-for-github-copilot">Custom instructions for GitHub Copilot</a></p> </li> <li> <p><a href="https://docs.github.com/en/copilot/getting-started-with-github-copilot">Getting started with Copilot</a></p> </li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Cross file rename', N'<h3>Summary</h3> <p>In this refactor exercise you will use <strong>GitHub Copilot Chat</strong> to rename every occurrence of the class <code>User</code> to <code>Member</code> across your repository. Copilot will propose bulk edits update imports and you will finish by running your build or test suite. Allocate around twenty minutes.</p> <h3>What you will learn</h3> <ul> <li> <p>Prompting Copilot Chat for a project wide rename.</p> </li> <li> <p>Reviewing bulk edit suggestions before applying them.</p> </li> <li> <p>Running build or test commands to verify a large refactor.</p> </li> <li> <p>Committing refactor changes with confidence.</p> </li> </ul> <h3>Before you start</h3> <p>Ensure Copilot Chat is enabled in <strong>your IDE</strong> for example VS Code JetBrains or Visual Studio. If you are using a compatible editor you may switch to EDIT mode. See references section below for instructions. Confirm your project builds cleanly and that you have a working test runner such as Jest PyTest JUnit or xUnit.</p> <h3>Steps</h3> <ul> <li> <p><strong>Step 1.</strong> Open any file that defines or references the class <code>User</code>.</p> </li> <li> <p><strong>Step 2.</strong> Launch Copilot Chat and type <code>Rename class User to Member across the repo update imports</code> then press Enter.</p> </li> <li> <p><strong>Step 3.</strong> Copilot displays a list of bulk edits. Review each change to confirm file paths and renamed symbols are correct.</p> </li> <li> <p><strong>Step 4.</strong> Approve the bulk edits. Copilot will commit the changes to your working tree.</p> </li> <li> <p><strong>Step 5.</strong> Run your normal build or test command such as <code>npm test</code> <code>pytest</code> or <code>dotnet build</code>. Ensure everything compiles and all tests pass.</p> </li> <li> <p><strong>Step 6.</strong> If errors occur ask Copilot Chat follow up questions for example <code>Fix remaining User references</code> then re run the build.</p> </li> <li> <p><strong>Step 7.</strong> Commit the refactor with a message like <code>refactor: rename User to Member across codebase</code>. You may allow Copilot to draft the commit message at the prompt.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did Copilot list every file requiring a rename?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="cross-file-rename-q1" value="yes"> Yes</label><label><input type="radio" name="cross-file-rename-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did the project build or all tests pass after the rename?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="cross-file-rename-q2" value="yes"> Yes</label><label><input type="radio" name="cross-file-rename-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Did you commit the refactor with a descriptive message?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="cross-file-rename-q3" value="yes"> Yes</label><label><input type="radio" name="cross-file-rename-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li> <p><a href="https://learn.microsoft.com/en-us/visualstudio/ide/copilot-edits">Copilot Edits VS 2022 overview</a></p> </li> <li> <p><a href="https://code.visualstudio.com/docs/copilot/chat/copilot-edits">Copilot Edits VS Code overview</a></p> </li> <li> <p><a href="https://github.blog/changelog/2025-03-20-enhance-your-productivity-with-copilot-edits-in-jetbrains-ides/">Copilot Edits Jetbrains overview</a></p> </li> <li> <p><a href="https://docs.github.com/en/repositories/working-with-files/managing-files">Managing files in a repository</a></p> </li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Cross repo migration assistant', N'<h3>Summary</h3> <p>In this multi-repository automation task, you’ll use <strong>GitHub Copilot (Pro/Pro+/Business)</strong> inside VS Code to build GitHub Actions workflows that automate updates to import paths when a shared <code>utils</code> package is moved into a monorepo. You’ll create workflows for three satellite repositories—<code>repo-A</code>, <code>repo-B</code>, and <code>repo-C</code>—and validate the process with test runs and pull requests. Allocate thirty minutes.</p> <h3>What you will learn</h3> <ul> <li> <p>Using GitHub Copilot to generate Actions workflows for cross-repo automation.</p> </li> <li> <p>Updating import paths in satellite repositories in response to monorepo changes.</p> </li> <li> <p>Coordinating CI triggers and jobs using reusable workflows or dispatch events.</p> </li> <li> <p>Reviewing Copilot-assisted PRs and verifying test results.</p> </li> </ul> <h3>Before you start</h3> <p>Install the latest <strong>GitHub Copilot extension</strong> in VS Code and ensure you have an active subscription. Confirm push rights to the monorepo and all satellite repositories. Make sure each repo has working CI pipelines configured using GitHub Actions.</p> <h3>Steps</h3> <ul> <li> <p><strong>Step 1.</strong> Move the <code>utils</code> package into the monorepo under <code>packages/utils</code>. Commit and push the changes.</p> </li> <li> <p><strong>Step 2.</strong> In each satellite repository, open <code>.github/workflows/update-utils.yml</code> and use GitHub Copilot to generate a workflow that:</p> </li> <li> <p>Watches for new releases or changes in the monorepo’s <code>utils</code> package.</p> </li> <li>Checks out the code.</li> <li>Replaces old import paths (e.g., <code>../../utils</code>) with <code>@org/utils</code>.</li> <li> <p>Creates a pull request with the updated imports.</p> </li> <li> <p><strong>Step 3.</strong> Push the workflow file and manually trigger it using the GitHub Actions UI or through a <code>repository_dispatch</code> event from the monorepo.</p> </li> <li> <p><strong>Step 4.</strong> Review the pull request opened by the GitHub Action in each repository. Confirm the import path updates are accurate.</p> </li> <li> <p><strong>Step 5.</strong> Wait for CI to complete in each satellite repo. If needed, prompt Copilot with follow-up requests like <code>Fix broken tests after utils migration</code> to generate patches.</p> </li> <li> <p><strong>Step 6.</strong> Once all builds pass, merge the pull requests in <code>repo-A</code>, <code>repo-B</code>, and <code>repo-C</code>.</p> </li> <li> <p><strong>Step 7.</strong> Clean up any obsolete <code>utils</code> folders in satellite repos and confirm that your imports rely only on the monorepo package.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did you use Copilot to create a GitHub Action workflow in each satellite repo?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="cross-repo-migration-assistant-q1" value="yes"> Yes</label><label><input type="radio" name="cross-repo-migration-assistant-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did the workflows open pull requests with correct import path updates?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="cross-repo-migration-assistant-q2" value="yes"> Yes</label><label><input type="radio" name="cross-repo-migration-assistant-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Did all tests pass and changes get merged?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="cross-repo-migration-assistant-q3" value="yes"> Yes</label><label><input type="radio" name="cross-repo-migration-assistant-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li> <p><a href="https://docs.github.com/en/actions/using-workflows">Using GitHub Actions workflows</a></p> </li> <li> <p><a href="https://docs.github.com/en/actions/using-workflows/events-that-trigger-workflows#repository_dispatch">Triggering workflows across repositories</a></p> </li> <li> <p><a href="https://code.visualstudio.com/docs/copilot/chat/chat-agent-mode">Copilot Agents overview</a></p> </li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Custom Agent Mode', N'<h3>Summary</h3> <p>In this advanced exercise, you will create a <strong>.agent.md</strong> custom agent called <em>CI/CD Release Manager</em> that instructs GitHub Copilot to assist with release pipelines, tagging, and changelog generation. Estimated time: thirty minutes.</p> <h3>What you will learn</h3> <ul> <li>Creating a <code>.agent.md</code> file to define a custom Copilot agent.</li> <li>Guiding Copilot''s responses to focus on CI/CD workflows.</li> <li>Integrating and selecting a custom agent in VS Code Copilot Chat.</li> <li>Applying persona-driven suggestions to automate release processes.</li> </ul> <h3>Before you start</h3> <p>Ensure you have the latest GitHub Copilot Chat extension in VS Code, and a repository containing at least one GitHub Actions workflow for CI/CD.</p> <h3>Steps</h3> <ul> <li><strong>Step 1.</strong> Create a folder <code>.github/agents</code> in your repo.</li> <li><strong>Step 2.</strong> Add a file <code>ci-cd-release-manager.agent.md</code> with agent instructions, limiting scope to CI/CD YAML edits, semantic versioning, and changelog automation. Refer to the <a href="https://code.visualstudio.com/docs/copilot/customization/custom-agents">Custom agents documentation</a> for guidance on structuring the agent file.</li> <li><strong>Step 3.</strong> <strong>Configure Custom Agents</strong> from the agents dropdown to discover the new agent.</li> <li><strong>Step 4.</strong> In Copilot Chat, select the <strong>CI/CD Release Manager</strong> agent from the agents dropdown.</li> <li><strong>Step 5.</strong> Prompt: <code>Prepare a GitHub Actions workflow to handle semantic version bumping based on commit messages and auto-generate a changelog.</code></li> <li><strong>Step 6.</strong> Review, refine, and commit the generated workflow.</li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Was the custom agent selected and activated successfully?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="custom-agent-mode-q1" value="yes"> Yes</label><label><input type="radio" name="custom-agent-mode-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did Copilot suggest a workflow following persona guidelines?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="custom-agent-mode-q2" value="yes"> Yes</label><label><input type="radio" name="custom-agent-mode-q2" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li><a href="https://code.visualstudio.com/docs/copilot/customization/custom-agents">Custom agents in VS Code</a></li> <li><a href="https://docs.github.com/en/actions">GitHub Actions documentation</a></li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Doc to spec converter', N'<h3>Summary</h3> <p>In this exercise you will use <strong>GitHub Copilot Agents</strong> inside VS Code to summarise a set of commits that modified your module (eg:Authentication module). You will ask the Agent <code>Summarise auth module changes across commits a1…a6 in this repo</code> then review the generated overview. Plan about fifteen minutes.</p> <h3>What you will learn</h3> <ul> <li> <p>Enabling Copilot Agent mode in VS Code.</p> </li> <li> <p>Prompting an Agent to analyse multiple commits.</p> </li> <li> <p>Reading a concise natural language diff summary.</p> </li> <li> <p>Sharing the summary with your team or attaching it to a pull request.</p> </li> </ul> <h3>Before you start</h3> <p>Install the latest <strong>GitHub Copilot</strong> extension in VS Code and enable Agent mode under <strong>Settings &gt; GitHub Copilot &gt; Agents</strong>. Ensure you have at least six sequential commits that touched the module (ex: authentication) and know their hashes (for example <code>a1</code> through <code>a6</code>).</p> <h3>Steps</h3> <ul> <li> <p><strong>Step 1.</strong> Open your repository in VS Code and switch to the Copilot panel. Click <strong>Agent</strong> to enter Agent mode.</p> </li> <li> <p><strong>Step 2.</strong> In the Agent prompt type <code>Summarise auth module changes across commits a1…a6 in this repo</code> then press Enter.</p> </li> <li> <p><strong>Step 3.</strong> Wait while the Agent calls the repo search tool and analyses each commit. A structured summary appears describing added files removed functions and key behaviour changes.</p> </li> <li> <p><strong>Step 4.</strong> Copy the summary to your clipboard or click <strong>Insert to editor</strong> to save it in <code>docs/auth-change-log.md</code>.</p> </li> <li> <p><strong>Step 5.</strong> If any detail is unclear ask a follow up question such as <code>Show code diff for the login validator refactor</code> and review the answer.</p> </li> <li> <p><strong>Step 6.</strong> Commit the summary file on a new branch and push for review.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did the Agent return a clear description of all six commits?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="doc-to-spec-converter-q1" value="yes"> Yes</label><label><input type="radio" name="doc-to-spec-converter-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did you ask at least one follow up question to clarify a change?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="doc-to-spec-converter-q2" value="yes"> Yes</label><label><input type="radio" name="doc-to-spec-converter-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Did you save or share the summary with your team?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="doc-to-spec-converter-q3" value="yes"> Yes</label><label><input type="radio" name="doc-to-spec-converter-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li><a href="https://code.visualstudio.com/docs/copilot/chat/chat-agent-mode">Copilot Agents overview</a></li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Docstring on demand', N'<h3>Summary</h3> <p>This exercise shows how to let <strong>GitHub Copilot</strong> write documentation for your own code. You will insert a docstring marker above an undocumented function or class and accept the generated text. The task should take about fifteen minutes.</p> <h3>What you will learn</h3> <ul> <li> <p>Triggering docstring generation with <code>/**</code> in languages such as JavaScript Java and C#.</p> </li> <li> <p>Triggering docstring generation with <code>"""</code> in Python.</p> </li> <li> <p>Accepting or cycling through Copilot suggestions to document code quickly.</p> </li> <li> <p>Reviewing and editing generated documentation for clarity and accuracy.</p> </li> </ul> <h3>Prerequisites</h3> <p>Make sure GitHub Copilot is active in <strong>your IDE</strong> (VS Code JetBrains Visual Studio or Neovim). Open a repository you own or maintain so you can save changes.</p> <h3>Steps</h3> <ul> <li> <p><strong>Step 1.</strong> Find a function or class in your code that has no documentation.</p> </li> <li> <p><strong>Step 2.</strong> Place the cursor on the line directly above that definition.</p> </li> <li> <p><strong>Step 3.</strong> Type <code>/**</code> if you are in JavaScript Java or C# or type <code>"""</code> if you are in Python then press Enter.</p> </li> <li> <p><strong>Step 4.</strong> Wait for Copilot to suggest a complete docstring. Press <strong>Tab</strong> to accept or use <strong>Alt ]</strong> or <strong>Option ]</strong> to view other versions.</p> </li> <li> <p><strong>Step 5.</strong> Read the generated text. Add or correct details so that parameters return values and side effects are clear.</p> </li> <li> <p><strong>Step 6.</strong> Repeat Steps 1 to 5 on one more function in another language file if possible.</p> </li> <li> <p><strong>Step 7.</strong> Commit your changes with a message that mentions added documentation. You may let Copilot draft the commit message at the prompt.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did Copilot generate a docstring without manual typing?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="docstring-on-demand-q1" value="yes"> Yes</label><label><input type="radio" name="docstring-on-demand-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did you cycle through more than one suggestion before accepting?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="docstring-on-demand-q2" value="yes"> Yes</label><label><input type="radio" name="docstring-on-demand-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Did you edit the generated docstring to better fit your code style?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="docstring-on-demand-q3" value="yes"> Yes</label><label><input type="radio" name="docstring-on-demand-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li> <p><a href="https://docs.github.com/en/copilot/getting-started-with-github-copilot">Getting started with GitHub Copilot</a></p> </li> <li> <p><a href="https://docs.github.com/en/copilot/quickstart">Quickstart guide for common Copilot tasks</a></p> </li> <li> <p><a href="https://github.blog/ai-and-ml/github-copilot/documenting-and-explaining-legacy-code-with-github-copilot-tips-and-examples/">Using Copilot in VS Code</a></p> </li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Explain complex diff with Agents', N'<h3>Summary</h3> <p>In this exercise you will use <strong>GitHub Copilot Agents</strong> inside VS Code to summarise a set of commits that modified your module (eg:Authentication module). You will ask the Agent <code>Summarise auth module changes across commits a1…a6 in this repo</code> then review the generated overview. Plan about fifteen minutes.</p> <h3>What you will learn</h3> <ul> <li> <p>Enabling Copilot Agent mode in VS Code.</p> </li> <li> <p>Prompting an Agent to analyse multiple commits.</p> </li> <li> <p>Reading a concise natural language diff summary.</p> </li> <li> <p>Sharing the summary with your team or attaching it to a pull request.</p> </li> </ul> <h3>Before you start</h3> <p>Install the latest <strong>GitHub Copilot</strong> extension in VS Code and enable Agent mode under <strong>Settings &gt; GitHub Copilot &gt; Agents</strong>. Ensure you have at least six sequential commits that touched the module (ex: authentication) and know their hashes (for example <code>a1</code> through <code>a6</code>).</p> <h3>Steps</h3> <ul> <li> <p><strong>Step 1.</strong> Open your repository in VS Code and switch to the Copilot panel. Click <strong>Agent</strong> to enter Agent mode.</p> </li> <li> <p><strong>Step 2.</strong> In the Agent prompt type <code>Summarise auth module changes across commits a1…a6 in this repo</code> then press Enter.</p> </li> <li> <p><strong>Step 3.</strong> Wait while the Agent calls the repo search tool and analyses each commit. A structured summary appears describing added files removed functions and key behaviour changes.</p> </li> <li> <p><strong>Step 4.</strong> Copy the summary to your clipboard or click <strong>Insert to editor</strong> to save it in <code>docs/auth-change-log.md</code>.</p> </li> <li> <p><strong>Step 5.</strong> If any detail is unclear ask a follow up question such as <code>Show code diff for the login validator refactor</code> and review the answer.</p> </li> <li> <p><strong>Step 6.</strong> Commit the summary file on a new branch and push for review.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did the Agent return a clear description of all six commits?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="explain-complex-diff-with-agents-q1" value="yes"> Yes</label><label><input type="radio" name="explain-complex-diff-with-agents-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did you ask at least one follow up question to clarify a change?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="explain-complex-diff-with-agents-q2" value="yes"> Yes</label><label><input type="radio" name="explain-complex-diff-with-agents-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Did you save or share the summary with your team?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="explain-complex-diff-with-agents-q3" value="yes"> Yes</label><label><input type="radio" name="explain-complex-diff-with-agents-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li><a href="https://code.visualstudio.com/docs/copilot/chat/chat-agent-mode">Copilot Agents overview</a></li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Explain my PR', N'<h3>Summary</h3> <p>This activity shows how to use <strong>GitHub Copilot Explain</strong> to create a human readable summary of a pull request. You will open a real PR you just raised click the Explain button on the Files changed tab then post the generated text as a PR comment. The task should take about fifteen minutes.</p> <h3>What you will learn</h3> <ul> <li> <p>Locating the Copilot Explain option on the Files changed tab of a pull request.</p> </li> <li> <p>Generating a natural language summary of code changes.</p> </li> <li> <p>Posting Copilot output as a comment to help reviewers.</p> </li> <li> <p>Adding context or edits to improve the summary before submission.</p> </li> </ul> <h3>Prerequisites</h3> <p>Ensure you have a GitHub repository in <strong>Github Enterprise</strong> where you can open pull requests. Push at least one commit and create a new PR that modifies multiple lines so the diff is non trivial. Make sure Copilot Explain for pull requests is enabled under repository Settings &gt; Copilot.</p> <h3>Steps</h3> <ul> <li> <p><strong>Step 1.</strong> Navigate to your pull request on GitHub and click the <strong>Files changed</strong> tab.</p> </li> <li> <p><strong>Step 2.</strong> Locate the <strong>Copilot Explain</strong> button near the top of the diff view and click it.</p> </li> <li> <p><strong>Step 3.</strong> Wait for Copilot to produce a summary. Review the text and copy it to your clipboard.</p> </li> <li> <p><strong>Step 4.</strong> Scroll to the PR conversation tab click <strong>Comment</strong> and paste the summary.</p> </li> <li> <p><strong>Step 5.</strong> Add any missing context such as ticket numbers or performance notes then submit the comment.</p> </li> <li> <p><strong>Step 6.</strong> Notify your reviewers that an AI generated summary is available to speed up review.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did Copilot Explain generate a clear summary without errors?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="explain-my-pr-q1" value="yes"> Yes</label><label><input type="radio" name="explain-my-pr-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did you post the summary as a comment in the pull request conversation?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="explain-my-pr-q2" value="yes"> Yes</label><label><input type="radio" name="explain-my-pr-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Did you enhance the summary with extra context before submitting?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="explain-my-pr-q3" value="yes"> Yes</label><label><input type="radio" name="explain-my-pr-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li> <p><a href="https://docs.github.com/en/copilot/responsible-use-of-github-copilot-features/responsible-use-of-github-copilot-pull-request-summaries">Copilot for pull requests</a></p> </li> <li> <p><a href="https://docs.github.com/en/github/collaborating-with-pull-requests">Collaborating with pull requests</a></p> </li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Ghost Text 101', N'<h3>Summary</h3> <p>In this micro-exercise you will practise Copilot’s “ghost text” inline completion on real code in your own repository. You will (a) finish a half-implemented function in your primary language, then (b) repeat the experiment in a different language file that already lives in the same repo, all in 15-20 minutes.</p> <h3>What you will learn</h3> <ul> <li> <p>Triggering and accepting Copilot’s inline suggestions (“ghost text”).</p> </li> <li> <p>Prompting better suggestions with meaningful names and comments.</p> </li> <li> <p>Cycling through alternative completions with the keyboard.</p> </li> <li> <p>Comparing Copilot behaviour across two different programming languages.</p> </li> </ul> <h3>Prerequisites</h3> <p>Make sure GitHub Copilot is enabled in your IDE of choice (VS Code, JetBrains, Visual Studio, Neovim…). Open a repository you worked on recently, no starter project needed.</p> <h3>Step-by-step tutorial</h3> <ul> <li> <div class="question-item"><ol> <li>Pick a partially written function<br /> Locate a function or method you began last week but never finished. Tip: search for “TODO” comments or empty method bodies. If you don’t have one, create a new function and leave it partly stubbed to simulate a work-in-progress.</li> </ol> </li> <li> <ol start="2"> <li>Set the stage for Copilot<br /> Add a one-line comment describing the intent (e.g., <code>// Return the sum of all positive numbers</code>). Good context helps Copilot suggest higher-quality code.</li> </ol> </li> <li> <ol start="3"> <li>Start typing... accept the ghost text<br /> Begin the first line of the implementation and pause. When the grey suggestion appears:</li> </ol> </li> <li> <p>Press Tab (? ] / Alt ] to cycle variants) to accept.</p> </li> <li> <p>Optionally reject (Esc) and keep typing to refine the prompt.</p> </li> <li> <ol start="4"> <li>Review &amp; adjust<br /> Read the generated code. If it compiles and meets your style, keep it; otherwise edit freely.</li> </ol> </li> <li> <ol start="5"> <li>Try again in another language file<br /> Open a file in a different language that already exists in the repo (e.g., Python if you started in JS). Repeat steps 2-4 and observe how suggestions adapt.</li> </ol> </li> <li> <ol start="6"> <li>Commit your work<br /> Run tests or build as usual, then commit with a Copilot-generated commit message (optional).</li> </ol> </li> </ul> <h3>Mini-quiz</h3> <ol> <li>Did Copilot suggest a complete, runnable function body?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="ghost-text-101-q1" value="yes"> Yes</label><label><input type="radio" name="ghost-text-101-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did you use the keyboard shortcut to cycle through alternative suggestions?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="ghost-text-101-q2" value="yes"> Yes</label><label><input type="radio" name="ghost-text-101-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Did you repeat the exercise in a second language file and notice any differences?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="ghost-text-101-q3" value="yes"> Yes</label><label><input type="radio" name="ghost-text-101-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li> <p><a href="https://docs.github.com/en/copilot/getting-started-with-github-copilot">Copilot Quickstart docs</a></p> </li> <li> <p><a href="https://code.visualstudio.com/docs/editor/intellisense#_inline-suggestions">VS Code inline suggestion keys</a></p> </li> <li> <p><a href="https://githubnext.com/projects/copilot-cli">Copilot CLI (ghost text on the command line)</a></p> </li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Internationalisation sweep', N'<h3>Summary</h3> <p>In this localisation exercise you will use <strong>GitHub Copilot Chat in EDIT mode</strong> to internationalise a React view. Copilot will wrap hard coded user facing strings in <code>t()</code> calls and create an <code>en.json</code> translation file. You will then verify that the application still renders correctly. Plan about twenty minutes.</p> <h3>What you will learn</h3> <ul> <li> <p>Finding hard coded strings in a React component.</p> </li> <li> <p>Prompting Copilot Chat to apply <code>t()</code> wrappers automatically.</p> </li> <li> <p>Generating an <code>en.json</code> translation catalogue.</p> </li> <li> <p>Running and visually verifying the app after internationalisation.</p> </li> </ul> <h3>Before you start</h3> <p>Confirm Copilot Chat is enabled in <strong>your IDE</strong> such as VS Code or JetBrains. Ensure your React project uses a library like <code>react-i18next</code> and runs successfully with <code>npm start</code> or <code>yarn dev</code>.</p> <h3>Steps</h3> <ul> <li> <p><strong>Step 1.</strong> Open a React component that contains visible hard coded strings for example headings button labels or error messages.</p> </li> <li> <p><strong>Step 2.</strong> Select the whole component or the JSX section with text and open Copilot Chat in EDIT mode.</p> </li> <li> <p><strong>Step 3.</strong> Type <code>Wrap all user facing strings in t() and generate an en.json file</code> then press Enter.</p> </li> <li> <p><strong>Step 4.</strong> Copilot lists edits that replace each literal with <code>{t(''key'')}</code> and proposes an <code>en.json</code> object. Accept the edits and save the translation file under <code>src/locales/en.json</code>.</p> </li> <li> <p><strong>Step 5.</strong> Run <code>npm start</code> or your usual dev server and load the page in a browser. Check that every string appears and no translation key is missing.</p> </li> <li> <p><strong>Step 6.</strong> Commit the changes including the updated component and <code>en.json</code> with a descriptive message.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did Copilot replace every hard coded string with a <code>t()</code> call?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="internationalisation-sweep-q1" value="yes"> Yes</label><label><input type="radio" name="internationalisation-sweep-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did the generated <code>en.json</code> include keys for each wrapped string?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="internationalisation-sweep-q2" value="yes"> Yes</label><label><input type="radio" name="internationalisation-sweep-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Did the application render correctly after the change?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="internationalisation-sweep-q3" value="yes"> Yes</label><label><input type="radio" name="internationalisation-sweep-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li> <p><a href="https://react.i18next.com/">react-i18next documentation</a></p> </li> <li> <p><a href="https://learn.microsoft.com/en-us/visualstudio/ide/copilot-edits">Copilot Edits VS 2022 overview</a></p> </li> <li> <p><a href="https://code.visualstudio.com/docs/copilot/chat/copilot-edits">Copilot Edits VS Code overview</a></p> </li> <li> <p><a href="https://github.blog/changelog/2025-03-20-enhance-your-productivity-with-copilot-edits-in-jetbrains-ides/">Copilot Edits Jetbrains overview</a></p> </li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Keyboard only hero', N'<h3>Summary</h3> <p>In this keyboard only challenge you will add a small new function to your project using GitHub Copilot completions without touching the mouse. You will use shortcut keys to cycle through suggestions accept code and record how long the task takes. Plan about fifteen minutes.</p> <h3>What you will learn</h3> <ul> <li> <p>Starting Copilot inline completions with the keyboard.</p> </li> <li> <p>Moving through alternative suggestions using <code>Alt ]</code> or <code>Option ]</code>.</p> </li> <li> <p>Accepting code with <code>Tab</code> and dismissing with <code>Esc</code>.</p> </li> <li> <p>Measuring productivity gains when you avoid the mouse.</p> </li> </ul> <h3>Prerequisites</h3> <p>Ensure GitHub Copilot is active in <strong>your IDE</strong> (VS Code JetBrains Visual Studio or Neovim). Check that the inline completion shortcuts match your keymap. Have a stopwatch or phone timer ready.</p> <h3>Steps</h3> <ul> <li> <p><strong>Step 1.</strong> Decide on a simple new function for example <code>calculateAverage</code> that you can add to an existing file.</p> </li> <li> <p><strong>Step 2.</strong> Start your timer then move the cursor to the location where the new function should go.</p> </li> <li> <p><strong>Step 3.</strong> Type the function signature and pause. When Copilot shows a suggestion press <strong>Tab</strong> to accept or use <strong>Alt ]</strong> or <strong>Option ]</strong> to view other completions.</p> </li> <li> <p><strong>Step 4.</strong> Continue using only the keyboard to build out the body of the function. Use <strong>Esc</strong> to reject any unwanted lines and type more context as needed.</p> </li> <li> <p><strong>Step 5.</strong> Stop the timer when the function completes after edits. Note the time and write it down.</p> </li> <li> <p><strong>Step 6.</strong> Run your normal tests or build command to confirm the new function works.</p> </li> <li> <p><strong>Step 7.</strong> Commit the change. You may let Copilot suggest the commit message by pausing at the prompt.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did you complete the task without using the mouse?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="keyboard-only-hero-q1" value="yes"> Yes</label><label><input type="radio" name="keyboard-only-hero-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did you cycle through at least one alternative suggestion with the shortcut keys?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="keyboard-only-hero-q2" value="yes"> Yes</label><label><input type="radio" name="keyboard-only-hero-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Did you record the time taken and compare it to a mouse based workflow?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="keyboard-only-hero-q3" value="yes"> Yes</label><label><input type="radio" name="keyboard-only-hero-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li> <p><a href="https://code.visualstudio.com/docs/reference/default-keybindings">Copilot keyboard shortcuts overview</a></p> </li> <li> <p><a href="https://code.visualstudio.com/docs/editor/intellisense">Inline suggestions in VS Code</a></p> </li> <li> <p><a href="https://code.visualstudio.com/docs/setup/mac">Visual Studio Code on macOS</a></p> </li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Language model pair review', N'<h3>Summary</h3> <p>This activity shows how to include <strong>GitHub Copilot</strong> as an automated reviewer on a pull request. You will assign Copilot to your PR respond to at least one AI generated comment then merge the pull request. The exercise takes about fifteen minutes.</p> <h3>What you will learn</h3> <ul> <li> <p>Adding Copilot as a reviewer on a pull request.</p> </li> <li> <p>Reading and interpreting AI review comments.</p> </li> <li> <p>Responding to or applying suggested changes.</p> </li> <li> <p>Merging the pull request after AI and human approval.</p> </li> </ul> <h3>Prerequisites</h3> <p>Ensure you have <strong>Copilot Enterprise</strong> and Copilot code review is enabled in your repository settings. If unsure, check with your GitHub admin. Have a pull request ready that contains meaningful changes but is not yet merged.</p> <h3>Steps</h3> <ul> <li> <p><strong>Step 1.</strong> Open your pull request on GitHub and click <strong>Reviewers</strong>.</p> </li> <li> <p><strong>Step 2.</strong> Search for and select <strong>GitHub Copilot</strong> then wait while the AI review runs.</p> </li> <li> <p><strong>Step 3.</strong> Refresh the page when Copilot comments appear. Read each comment carefully.</p> </li> <li> <p><strong>Step 4.</strong> Choose at least one AI suggestion to address. Reply with a note or push a follow up commit that resolves the feedback.</p> </li> <li> <p><strong>Step 5.</strong> Mark the conversation as resolved when you are satisfied.</p> </li> <li> <p><strong>Step 6.</strong> Once all reviewers including Copilot have approved click <strong>Merge pull request</strong>.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did Copilot provide review comments on your pull request?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="language-model-pair-review-q1" value="yes"> Yes</label><label><input type="radio" name="language-model-pair-review-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did you respond to or act on at least one AI comment?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="language-model-pair-review-q2" value="yes"> Yes</label><label><input type="radio" name="language-model-pair-review-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Did you merge the pull request after all approvals?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="language-model-pair-review-q3" value="yes"> Yes</label><label><input type="radio" name="language-model-pair-review-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li> <p><a href="https://docs.github.com/en/copilot/using-github-copilot/code-review/using-copilot-code-review">Copilot code review overview</a></p> </li> <li> <p><a href="https://docs.github.com/en/pull-requests/collaborating-with-pull-requests">Collaborating on pull requests</a></p> </li> <li> <p><a href="https://docs.github.com/en/copilot/getting-started-with-github-copilot">Getting started with Copilot</a></p> </li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Local Agent', N'<h3>Summary</h3> <p>In this exercise you will explore the three built-in local agent modes in GitHub Copilot Chat: <strong>Agent</strong>, <strong>Plan</strong>, and <strong>Ask</strong>. Each mode is designed for a different workflow, from autonomous multi-step coding to codebase exploration. Expect to spend twenty to thirty minutes.</p> <h3>What you will learn</h3> <ul> <li>Switching between Agent, Plan, and Ask modes in Copilot Chat.</li> <li>Using Agent mode for autonomous multi-file edits with inline diffs.</li> <li>Using Plan mode to generate an implementation plan before writing code.</li> <li>Using Ask mode to answer codebase questions without making changes.</li> <li>Reviewing checkpoints and undoing agent actions.</li> </ul> <h3>Before you start</h3> <p>Ensure VS Code has the latest GitHub Copilot Chat extension. Enable agent mode in settings (<code>chat.agent.enabled</code>). Open a repository with enough code to make multi-file tasks meaningful.</p> <h3>Steps</h3> <ul> <li> <p><strong>Step 1.</strong> Open Copilot Chat and use the agents dropdown to switch to <strong>Ask</strong> mode. Enter: <code>Explain how authentication is handled in this project.</code> Review the response, which references specific files without making edits.</p> </li> <li> <p><strong>Step 2.</strong> Switch to <strong>Plan</strong> mode. Enter: <code>Add input validation to all API controller methods.</code> Copilot generates a step-by-step plan listing files to change and what to modify.</p> </li> <li> <p><strong>Step 3.</strong> Review the generated plan. Edit or reorder steps if needed. When satisfied, click <strong>Start Implementation</strong> to hand off to Agent mode.</p> </li> <li> <p><strong>Step 4.</strong> Observe Agent mode executing each step. Inline diffs appear in the editor as files are modified. A checkpoint is created after each step so you can undo individual changes.</p> </li> <li> <p><strong>Step 5.</strong> Open the Timeline view or the undo history to inspect checkpoints. Roll back one change to see how Copilot restores the previous state.</p> </li> <li> <p><strong>Step 6.</strong> Start a fresh Agent mode session and enter: <code>Write unit tests for the user service module.</code> Watch the agent create test files, add imports, and run tests autonomously.</p> </li> <li> <p><strong>Step 7.</strong> Review all changes in the Source Control panel and commit them.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did you successfully use Ask mode to get a codebase explanation without any file edits?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="local-agent-q1" value="yes"> Yes</label><label><input type="radio" name="local-agent-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did Plan mode generate a clear implementation plan that you could review before execution?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="local-agent-q2" value="yes"> Yes</label><label><input type="radio" name="local-agent-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Did Agent mode apply inline diffs and create checkpoints you could inspect and undo?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="local-agent-q3" value="yes"> Yes</label><label><input type="radio" name="local-agent-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li> <p><a href="https://code.visualstudio.com/docs/copilot/agents/local-agents">Local agents in VS Code</a></p> </li> <li> <p><a href="https://code.visualstudio.com/docs/copilot/chat/chat-agent-mode">Copilot Chat agent mode tutorial</a></p> </li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Multimodal bug hunt with Vision', N'<h3>Summary</h3> <p>In this multimodal bug hunt you will capture a screenshot of a visual bug in your own application and feed it to <strong>GitHub Copilot Agent mode with Vision Preview</strong>. The Agent will compare the screenshot to the Figma design export checked into your repository and propose code fixes. You will apply the patch then verify the UI renders correctly. Reserve about twenty minutes.</p> <h3>What you will learn</h3> <ul> <li> <p>Capturing and attaching UI screenshots to Copilot Chat Vision.</p> </li> <li> <p>Referencing a Figma design export stored in the repo.</p> </li> <li> <p>Prompting the Agent to generate code fixes based on visual differences.</p> </li> <li> <p>Running and visually verifying the application after applying the patch.</p> </li> </ul> <h3>Before you start</h3> <p>Install the latest <strong>GitHub Copilot</strong> extension in VS Code and enable both Agent mode and Vision under <strong>Settings &gt; GitHub Copilot</strong>. Ensure your repository contains the Figma design export for the affected screen for example <code>design/login-page.png</code>. Start your development server with <code>npm start</code> <code>yarn dev</code> or similar so you can reproduce the bug.</p> <h3>Steps</h3> <ul> <li> <p><strong>Step 1.</strong> Reproduce the visual bug in your browser then take a screenshot (for example <code>bug.png</code>) and save it in the repo under <code>docs/bugs/</code>.</p> </li> <li> <p><strong>Step 2.</strong> Create a new branch named <code>vision-bugfix</code> with <code>git checkout -b vision-bugfix</code> or via the source control panel.</p> </li> <li> <p><strong>Step 3.</strong> Open Copilot Chat and switch to <strong>Agent</strong> mode.</p> </li> <li> <p><strong>Step 4.</strong> Drag <code>docs/bugs/bug.png</code> into the chat box. After the thumbnail appears drag the Figma export <code>design/login-page.png</code> into the same prompt.</p> </li> <li> <p><strong>Step 5.</strong> Type <code>Compare the bug screenshot to the Figma design and propose code fixes</code> then press Enter.</p> </li> <li> <p><strong>Step 6.</strong> Review the plan and patch the Agent suggests. Accept the patch with <strong>Tab</strong> or paste it into the correct file then save changes.</p> </li> <li> <p><strong>Step 7.</strong> Refresh the browser running the dev server to confirm the UI now matches the design.</p> </li> <li> <p><strong>Step 8.</strong> Commit the fix with a descriptive message generated by you or drafted by Copilot then push the branch and open a pull request.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did the Agent highlight the exact visual differences between screenshot and design?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="multimodal-bug-hunt-with-vision-q1" value="yes"> Yes</label><label><input type="radio" name="multimodal-bug-hunt-with-vision-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did the generated patch compile and render without errors?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="multimodal-bug-hunt-with-vision-q2" value="yes"> Yes</label><label><input type="radio" name="multimodal-bug-hunt-with-vision-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Does the fixed page now match the Figma design when viewed in the browser?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="multimodal-bug-hunt-with-vision-q3" value="yes"> Yes</label><label><input type="radio" name="multimodal-bug-hunt-with-vision-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li> <p><a href="https://code.visualstudio.com/docs/copilot/chat/chat-agent-mode">Copilot Agents overview</a></p> </li> <li> <p><a href="https://help.figma.com/hc/en-us/articles/360040028114-Export-from-Figma-Design">Exporting frames from Figma</a></p> </li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Performance profiler assistant', N'<h3>Summary</h3> <p>In this performance tuning exercise you will choose a slow running method in your codebase and use <strong>GitHub Copilot Chat in EDIT mode</strong> to instrument it with a profiler in your language of choice. Copilot will then propose optimisations. You will benchmark the method before and after the changes to confirm an improvement. Plan roughly twenty minutes.</p> <h3>What you will learn</h3> <ul> <li> <p>Selecting and benchmarking a performance hotspot.</p> </li> <li> <p>Prompting Copilot Chat to add profiler instrumentation.</p> </li> <li> <p>Applying AI suggested optimisations safely.</p> </li> <li> <p>Comparing benchmark results before and after the refactor.</p> </li> </ul> <h3>Before you start</h3> <p>Confirm Copilot Chat is enabled in <strong>your IDE</strong> such as VS Code JetBrains or Visual Studio. Ensure you have a profiling tool available for your language for example <code>timeit</code> in Python BenchmarkDotNet in C Sharp or Node <code>node --prof</code>.</p> <h3>Steps</h3> <ul> <li> <p><strong>Step 1.</strong> Identify a method that is noticeably slow during normal execution or profiling.</p> </li> <li> <p><strong>Step 2.</strong> Benchmark the current implementation. For Python run <code>python -m timeit -s "from module import slow_method" "slow_method()"</code> or use your language equivalent. Record the result.</p> </li> <li> <p><strong>Step 3.</strong> Highlight the entire method then open Copilot Chat and type <code>Instrument this method with the built in profiler and suggest optimisations</code> then press Enter.</p> </li> <li> <p><strong>Step 4.</strong> Copilot will insert profiling code and list possible improvements such as memoisation avoiding redundant loops or using more efficient data structures. Accept the instrumentation first run it and observe the hottest lines.</p> </li> <li> <p><strong>Step 5.</strong> Apply one optimisation at a time following Copilot’s suggestions. Save your changes after each edit.</p> </li> <li> <p><strong>Step 6.</strong> Benchmark the optimised method using the same command as in Step 2. Compare the new runtime with the original.</p> </li> <li> <p><strong>Step 7.</strong> Once you confirm a measurable improvement commit the changes with a clear message possibly generated by Copilot.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did Copilot add profiler instrumentation without syntax errors?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="performance-profiler-assistant-q1" value="yes"> Yes</label><label><input type="radio" name="performance-profiler-assistant-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did the optimised method run faster than the original benchmark?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="performance-profiler-assistant-q2" value="yes"> Yes</label><label><input type="radio" name="performance-profiler-assistant-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Did you commit the profiler code removal or keep a clean final version?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="performance-profiler-assistant-q3" value="yes"> Yes</label><label><input type="radio" name="performance-profiler-assistant-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li> <p><a href="https://learn.microsoft.com/en-us/visualstudio/ide/copilot-edits">Copilot Edits VS 2022 overview</a></p> </li> <li> <p><a href="https://code.visualstudio.com/docs/copilot/chat/copilot-edits">Copilot Edits VS Code overview</a></p> </li> <li> <p><a href="https://github.blog/changelog/2025-03-20-enhance-your-productivity-with-copilot-edits-in-jetbrains-ides/">Copilot Edits Jetbrains overview</a></p> </li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'PRD - Stories - Code (voice-first)', N'<h3>Summary</h3> <p>In this end-to-end workflow you will start with a lightweight Product Requirements Document named <code>product-x.prd.md</code>. Using <strong>GitHub Copilot Chat in Agent mode with voice input</strong>you will:</p> <ul> <li>Extract epics user stories and acceptance criteria.</li> <li>Draft a Gherkin specification.</li> <li>Scaffold initial code stubs and tests on a new branch.</li> <li>Review the output, commit, and open a pull request.</li> <li>Plan about thirty minutes.</li> </ul> <h3>What you will learn</h3> <ul> <li> <p>Writing a concise PRD in markdown.</p> </li> <li> <p>Using Copilot Chat voice input to issue multi step prompts.</p> </li> <li> <p>Converting product language into epics user stories and Gherkin specs.</p> </li> <li> <p>Generating starter code and tests directly from requirements.</p> </li> </ul> <h3>Before you start</h3> <p>Install the <a href="https://marketplace.visualstudio.com/items?itemName=ms-vscode.vscode-speech">VS Code Speech</a> extension and enable microphone permissions for your browser or VS Code. Confirm you have write access to the repository and an available test runner (Jest PyTest JUnit or similar). Create <code>docs/product-x.prd.md</code> with a brief description of the new feature.</p> <h3>Steps</h3> <ul> <li> <p><strong>Step 1.</strong> Create and check out a branch called <code>feature-product-x</code> using <code>git checkout -b feature-product-x</code>.</p> </li> <li> <p><strong>Step 2.</strong> Open Copilot Chat and click the microphone icon (or press the assigned shortcut) then dictate: <code>Extract epics user stories and acceptance criteria from docs/product-x.prd.md</code>. Wait for Copilot to return structured lists.</p> </li> <li> <p><strong>Step 3.</strong> With voice still active ask: <code>Draft a Gherkin specification for these stories</code>. Accept the generated <code>product-x.feature</code> file into <code>tests/features/</code>.</p> </li> <li> <p><strong>Step 4.</strong> Speak: <code>Scaffold initial code stubs and unit tests in src/productX/</code>. Copilot adds empty classes functions and matching test files.</p> </li> <li> <p><strong>Step 5.</strong> Run your test suite with <code>npm test</code> <code>pytest</code> or equivalent. All tests should fail gracefully indicating todo stubs that await implementation.</p> </li> <li> <p><strong>Step 6.</strong> Stage all new files with <code>git add docs/product-x.prd.md src/ tests/</code> then commit. Let Copilot draft the commit message.</p> </li> <li> <p><strong>Step 7.</strong> Push the branch and open a pull request titled <code>feat: scaffold Product X epics stories Gherkin and stubs</code>.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did Copilot generate epics user stories and acceptance criteria from the PRD?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="prd-stories-code-voice-first-q1" value="yes"> Yes</label><label><input type="radio" name="prd-stories-code-voice-first-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did the Gherkin spec file save under <code>tests/features</code>?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="prd-stories-code-voice-first-q2" value="yes"> Yes</label><label><input type="radio" name="prd-stories-code-voice-first-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Did you commit and push the scaffold branch and open a pull request?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="prd-stories-code-voice-first-q3" value="yes"> Yes</label><label><input type="radio" name="prd-stories-code-voice-first-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li> <p><a href="https://code.visualstudio.com/docs/copilot/chat/chat-agent-mode">Copilot Agents overview</a></p> </li> <li> <p><a href="https://marketplace.visualstudio.com/items?itemName=ms-vscode.vscode-speech">VS Code Speech extension</a></p> </li> <li> <p><a href="https://code.visualstudio.com/docs/configure/accessibility/voice">Personalizing Copilot Voice</a></p> </li> <li> <p><a href="https://cucumber.io/docs/gherkin/">Gherkin syntax guide</a></p> </li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Prompt Templates', N'<h3>Summary</h3> <p>In this challenge, you will create a <strong>.prompt.md</strong> file that leverages GPT-5 Smart Mode to deeply analyze multi-step code logic, identify edge cases, and suggest improvements. You will also validate that the prompt is discovered by Copilot Chat, that Smart Mode is used, and that outputs are specific and actionable. Estimated time: ~20 minutes.</p> <h3>What you will learn</h3> <ul> <li>Creating reusable prompt templates in GitHub Copilot and structuring them for repeatable analysis.</li> <li>Triggering Smart Mode model routing for complex reasoning tasks and confirming the active model.</li> <li>Re-using and iterating on prompts across different code snippets to drive concrete refactors and tests.</li> </ul> <h3>Before you start</h3> <p>Ensure you are signed in to GitHub in VS Code, have the latest GitHub Copilot extension installed, GPT-5 Smart Mode available, and permission to add <code>.prompt.md</code> files to the repository. Keep a small snippet (30–120 lines) ready for analysis and make sure the repo opens cleanly in VS Code.</p> <h3>Steps</h3> <ul> <li><strong>Step 1.</strong> Create the folder <code>.github/prompts</code> at the repository root (create both directories if they don’t exist) and commit the empty folder with a placeholder file if required by your tooling.</li> <li><strong>Step 2.</strong> Add a new file <code>code-logic-explorer.prompt.md</code> containing a short title, a one-line goal, variables like <code>{{CODE_SNIPPET}}</code>, and explicit instructions, e.g., “analyze control flow, error handling, state transitions, time/space complexity, edge cases, and propose test cases.” Save the file.</li> <li><strong>Step 3.</strong> Commit the file and ensure Copilot discovers it: in VS Code, reload the window (Command Palette → “Developer: Reload Window”) or reopen the workspace so the prompt catalog refreshes.</li> <li><strong>Step 4.</strong> Open Copilot Chat and load the prompt. Use the prompt picker to select <em>code-logic-explorer</em> or reference it directly (e.g., “Use <em>code-logic-explorer</em> with the following code”). Paste your code into the <code>{{CODE_SNIPPET}}</code> slot using triple backticks.</li> <li><strong>Step 5.</strong> Confirm Smart Mode: start the run and watch for Copilot switching to GPT-5 Smart Mode for deeper reasoning. If Smart Mode doesn’t activate, check the model picker in Copilot Chat and manually select <em>GPT-5 mini</em>.</li> <li><strong>Step 6.</strong> Guide specificity: if the analysis feels generic, ask for concrete outputs—e.g., “list 5 edge cases with inputs/expected outputs,” “provide 3 unit tests in my test framework,” “explain risk of race conditions with a minimal example,” “estimate time/space complexity and cite hot paths.”</li> <li><strong>Step 7.</strong> Apply changes safely: create a new branch, implement the highest-value refactors suggested, and run your test suite (or create tests from the generated cases). Capture any performance or readability improvements.</li> <li><strong>Step 8.</strong> Iterate: re-run the same prompt against the updated code to verify that previously flagged issues are resolved and to surface second-order issues (e.g., error propagation, boundary conditions, I/O timeouts).</li> <li><strong>Step 9.</strong> Reuse: run the prompt on a second snippet (e.g., a sibling module or related function) to confirm portability. Tweak the prompt wording only if you consistently see gaps in the analysis.</li> <li><strong>Step 10.</strong> Troubleshooting quick fixes: if Smart Mode doesn’t trigger—open the model picker in Copilot Chat and select <em>GPT-5 mini</em>; if the prompt file isn’t recognized—verify the path is exactly <code>.github/prompts/</code>, the file ends with <code>.prompt.md</code>, commit and reload VS Code; if the output is too generic—narrow scope (smaller snippet), request numbered findings with code pointers and test cases, and ask for “fail-first” examples.</li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Was the prompt template discovered (correct path/name) and executed with your <code>{{CODE_SNIPPET}}</code>?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="prompt-templates-q1" value="yes"> Yes</label><label><input type="radio" name="prompt-templates-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did Copilot run in Smart Mode and produce specific, testable recommendations (edge cases, tests, refactors)?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="prompt-templates-q2" value="yes"> Yes</label><label><input type="radio" name="prompt-templates-q2" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li><a href="https://code.visualstudio.com/docs/copilot/copilot-customization">Customizing Copilot with prompt files in VS Code</a></li> <li><a href="https://github.blog/">Deep dives and tips on the GitHub Copilot Blog</a></li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'README booster', N'<h3>Summary</h3> <p>In this activity you will use <strong>GitHub Copilot Chat</strong> to add a new Setup or Contributing section to your project Readme. Copilot will draft the content you will review and edit then commit the updated file. Plan about fifteen minutes.</p> <h3>What you will learn</h3> <ul> <li> <p>Prompting Copilot Chat to generate markdown content.</p> </li> <li> <p>Editing AI generated text to match project style.</p> </li> <li> <p>Committing documentation changes to the repository.</p> </li> <li> <p>Previewing markdown to verify formatting.</p> </li> </ul> <h3>Prerequisites</h3> <p>Confirm Copilot Chat is active in <strong>your IDE</strong> such as VS Code JetBrains or Visual Studio. Ensure your repository has a Readme in the root folder.</p> <h3>Steps</h3> <ul> <li> <p><strong>Step 1.</strong> Open <code>README.md</code> at the top of your project and place the cursor where the new section should go.</p> </li> <li> <p><strong>Step 2.</strong> Open Copilot Chat and type <code>Draft a Setup section for this #codebase</code> or <code>Draft a Contributing section for this #codebase</code> then press Enter.</p> </li> <li> <p><strong>Step 3.</strong> Review the markdown Copilot returns. Use <strong>Tab</strong> to accept or copy and paste only the parts you need.</p> </li> <li> <p><strong>Step 4.</strong> Edit headings code blocks and command references to fit your tooling and style.</p> </li> <li> <p><strong>Step 5.</strong> Preview the markdown in your IDE to confirm links and formatting look correct.</p> </li> <li> <p><strong>Step 6.</strong> Stage the updated Readme with <code>git add README.md</code> or via the source control view.</p> </li> <li> <p><strong>Step 7.</strong> Commit the change letting Copilot suggest the commit message if you wish then push to remote.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did Copilot generate a complete markdown section without manual writing?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="readme-booster-q1" value="yes"> Yes</label><label><input type="radio" name="readme-booster-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did you edit the draft to align with project conventions?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="readme-booster-q2" value="yes"> Yes</label><label><input type="radio" name="readme-booster-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Did the updated Readme render correctly in preview or on GitHub?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="readme-booster-q3" value="yes"> Yes</label><label><input type="radio" name="readme-booster-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li> <p><a href="https://githubnext.com/projects/copilot-view/">Copilot codebase overview</a></p> </li> <li> <p><a href="https://docs.github.com/en/copilot/getting-started-with-github-copilot#documentation">Generating documentation with Copilot</a></p> </li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Refactor with confidence', N'<h3>Summary</h3> <p>In this activity you will use <strong>GitHub Copilot Chat</strong> to refactor a long method by extracting smaller helper methods while keeping behaviour unchanged. Copilot will also create unit tests first so you can confirm nothing breaks. The exercise should take about twenty minutes.</p> <h3>What you will learn</h3> <ul> <li> <p>Selecting a candidate for refactor in your own code.</p> </li> <li> <p>Prompting Copilot Chat to extract helper methods and generate tests up front.</p> </li> <li> <p>Running the new tests to verify behaviour before and after refactor.</p> </li> <li> <p>Committing refactor changes with confidence.</p> </li> </ul> <h3>Prerequisites</h3> <p>Ensure Copilot Chat is enabled in <strong>your IDE</strong> such as VS Code JetBrains or Visual Studio. Confirm your project has a working test runner like Jest PyTest JUnit or xUnit.</p> <h3>Steps</h3> <ul> <li> <p><strong>Step 1.</strong> Locate a method longer than about thirty lines that mixes multiple responsibilities.</p> </li> <li> <p><strong>Step 2.</strong> Highlight the entire method then open Copilot Chat.</p> </li> <li> <p><strong>Step 3.</strong> Type <code>Extract smaller methods write tests first keep behaviour</code> and press Enter.</p> </li> <li> <p><strong>Step 4.</strong> Copilot will propose unit tests followed by the refactor plan and code. Accept the tests first, save them in your test folder (if not create one) and then copy the refactored code.</p> </li> <li> <p><strong>Step 5.</strong> Run your test suite for example <code>npm test</code> <code>pytest</code> or <code>dotnet test</code>. All tests should pass confirming behaviour is intact.</p> </li> <li> <p><strong>Step 6.</strong> Review helper method names and visibility. Rename or adjust signatures if needed then rerun tests.</p> </li> <li> <p><strong>Step 7.</strong> Commit the changes with a descriptive message. You may let Copilot draft the commit message once your staged diff is ready.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did Copilot create unit tests before performing the refactor?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="refactor-with-confidence-q1" value="yes"> Yes</label><label><input type="radio" name="refactor-with-confidence-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did all tests pass after the new helper methods were added?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="refactor-with-confidence-q2" value="yes"> Yes</label><label><input type="radio" name="refactor-with-confidence-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Did you confirm that the refactored code reads more clearly than before?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="refactor-with-confidence-q3" value="yes"> Yes</label><label><input type="radio" name="refactor-with-confidence-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li> <p><a href="https://docs.github.com/en/copilot/using-github-copilot/guides-on-using-github-copilot/refactoring-code-with-github-copilot">Refactoring code with GitHub Copilot</a></p> </li> <li> <p><a href="https://github.blog/ai-and-ml/github-copilot/how-to-refactor-code-with-github-copilot/">How to refactor code with GitHub Copilot</a></p> </li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Say hi to Copilot Chat', N'<h3>Summary</h3> <p>In this exercise you will use <strong>GitHub Copilot Chat</strong> to understand and improve code that already exists in your repository. You will select a confusing block, ask Copilot Chat to explain it, then request a simpler rewrite. The entire task should take about twenty minutes.</p> <h3>What you will learn</h3> <ul> <li> <p>Opening Copilot Chat inside your IDE.</p> </li> <li> <p>Sending prompts that refer to selected code.</p> </li> <li> <p>Asking follow up questions to refine Copilot responses.</p> </li> <li> <p>Evaluating and applying a suggested rewrite to your own code.</p> </li> </ul> <h3>Prerequisites</h3> <p>Confirm that Copilot Chat is enabled in <strong>your IDE</strong> (use the Copilot sidebar in VS Code or the Copilot Chat tool window in JetBrains and Visual Studio). Work inside a repository you own or have permission to change.</p> <h3>Steps</h3> <ul> <li> <p><strong>Step 1.</strong> Select a block of code that you find hard to read or overly complex.</p> </li> <li> <p><strong>Step 2.</strong> With the code still highlighted open the Copilot Chat panel. In VS Code choose <strong>Copilot Chat</strong> from the Activity Bar. In JetBrains use <strong>View &gt; Tool Windows &gt; Copilot Chat</strong>.</p> </li> <li> <p><strong>Step 3.</strong> Type <code>Explain what this does</code> and press Enter. Read Copilot’s explanation and make sure it matches your intention.</p> </li> <li> <p><strong>Step 4.</strong> In the same conversation type <code>Can you suggest a simpler rewrite</code>. Copilot will return a refactored version of the selected code.</p> </li> <li> <p><strong>Step 5.</strong> Compare the suggested code with the original. If you prefer the new version paste it over the old block then run your tests or build command.</p> </li> <li> <p><strong>Step 6.</strong> Commit the change with a clear message. You can pause at the commit prompt and let Copilot propose a message if you wish.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did Copilot Chat provide an explanation that aligned with your understanding of the code?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="say-hi-to-copilot-chat-q1" value="yes"> Yes</label><label><input type="radio" name="say-hi-to-copilot-chat-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did you ask for and receive a simpler rewrite?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="say-hi-to-copilot-chat-q2" value="yes"> Yes</label><label><input type="radio" name="say-hi-to-copilot-chat-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Did the rewritten code compile or pass tests after you applied it?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="say-hi-to-copilot-chat-q3" value="yes"> Yes</label><label><input type="radio" name="say-hi-to-copilot-chat-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li> <p><a href="https://code.visualstudio.com/docs/copilot/chat/getting-started-chat">Getting started with Copilot Chat</a></p> </li> <li> <p><a href="https://learn.microsoft.com/en-us/visualstudio/ide/visual-studio-github-copilot-chat?view=vs-2022">Using Copilot Chat in VS Code</a></p> </li> <li> <p><a href="https://plugins.jetbrains.com/plugin/17718-github-copilot">Copilot Chat for JetBrains IDEs</a></p> </li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Security lens starter', N'<h3>Summary</h3> <p>In this security focused exercise you will copy a data access function from your repository that may contain a vulnerability. You will ask <strong>GitHub Copilot Chat</strong> to identify potential OWASP risks and provide a safer version of the code. Finally you will write a quick unit test to confirm the fix works. Allocate about twenty minutes.</p> <h3>What you will learn</h3> <ul> <li> <p>Sending real code snippets to Copilot Chat for security analysis.</p> </li> <li> <p>Mapping identified issues to OWASP categories.</p> </li> <li> <p>Generating a safer refactor that mitigates the risk.</p> </li> <li> <p>Writing a simple unit test to validate the secure behaviour.</p> </li> </ul> <h3>Prerequisites</h3> <p>Ensure Copilot Chat is enabled in <strong>your IDE</strong> for example VS Code JetBrains or Visual Studio. Confirm your project has a working test runner such as Jest PyTest JUnit or xUnit.</p> <h3>Steps</h3> <ul> <li> <p><strong>Step 1.</strong> In your code, select a data access function that may be vulnerable for example one that concatenates user input into a SQL string.</p> </li> <li> <p><strong>Step 2.</strong> Open Copilot Chat, note how the selected line numbers are automatically included and type <code>Identify OWASP risks and provide a safer version</code> then press Enter.</p> </li> <li> <p><strong>Step 3.</strong> Review the risks Copilot lists such as SQL Injection or Insecure Deserialization. Examine the safer code suggestion.</p> </li> <li> <p><strong>Step 4.</strong> Accept the secure refactor or copy it into a new branch for example <code>security-fix</code>.</p> </li> <li> <p><strong>Step 5.</strong> Ask Copilot Chat <code>Write a unit test that proves the fix blocks the vulnerability</code> then save the test file in your test directory.</p> </li> <li> <p><strong>Step 6.</strong> Run your tests with <code>npm test</code> <code>pytest</code> or <code>dotnet test</code>. Confirm they pass.</p> </li> <li> <p><strong>Step 7.</strong> Commit the secure code and tests with a descriptive message drafted by you or suggested by Copilot.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did Copilot correctly highlight at least one OWASP risk in your original code?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="security-lens-starter-q1" value="yes"> Yes</label><label><input type="radio" name="security-lens-starter-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did you implement the safer version without breaking existing functionality?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="security-lens-starter-q2" value="yes"> Yes</label><label><input type="radio" name="security-lens-starter-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Did the new unit test pass confirming the vulnerability is mitigated?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="security-lens-starter-q3" value="yes"> Yes</label><label><input type="radio" name="security-lens-starter-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li> <p><a href="https://docs.github.com/en/copilot/copilot-chat-cookbook/security-analysis/finding-existing-vulnerabilities-in-code">Finding existing vulnerabilities in code</a></p> </li> <li> <p><a href="https://owasp.org/www-project-top-ten">OWASP Top Ten reference</a></p> </li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Slash command speed run', N'<h3>Summary</h3> <p>This exercise shows how to use the <strong>/tests</strong> slash command in GitHub Copilot Chat to generate unit tests for code you just changed. You will invoke the command, accept the resulting test file, then run your usual test runner to confirm everything passes. Expect to finish in fifteen to twenty minutes.</p> <h3>What you will learn</h3> <ul> <li> <p>Opening Copilot Chat and issuing a slash command.</p> </li> <li> <p>Letting Copilot generate language specific unit tests.</p> </li> <li> <p>Saving the generated file into your repository.</p> </li> <li> <p>Running your existing test framework to validate results.</p> </li> </ul> <h3>Prerequisites</h3> <p>Ensure GitHub Copilot Chat is enabled in <strong>your IDE</strong> (VS Code JetBrains Visual Studio or Neovim). Confirm your project has a working test runner such as Jest PyTest JUnit or xUnit. Open a file you modified in the last commit.</p> <h3>Steps</h3> <ul> <li> <p><strong>Step 1.</strong> Place the cursor inside the file you recently edited. No need to select text.</p> </li> <li> <p><strong>Step 2.</strong> Open Copilot Chat. In VS Code click the Copilot icon in the Activity Bar and open a new local chat session, Agent or Ask mode. In JetBrains choose <strong>View &gt; Tool Windows &gt; Copilot Chat</strong>.</p> </li> <li> <p><strong>Step 3.</strong> In the chat box type <code>/tests</code> and press Enter. Copilot will respond with a proposed test file tailored to the file under the cursor.</p> </li> <li> <p><strong>Step 4.</strong> Review the generated code. Use <strong>Tab</strong> to accept or <strong>Esc</strong> to reject and retry. If accepted Copilot inserts the new test file in the correct folder.</p> </li> <li> <p><strong>Step 5.</strong> Run your normal test command such as <code>npm test</code> <code>pytest</code> or <code>dotnet test</code>. Confirm that all tests pass. <strong>Tip</strong> - Ask Copilot about how to run the tests manually</p> </li> <li> <p><strong>Step 6.</strong> Commit the new test file with a clear message. You can let Copilot draft the commit message if you pause at the prompt.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did Copilot create a test file without manual coding?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="slash-command-speed-run-q1" value="yes"> Yes</label><label><input type="radio" name="slash-command-speed-run-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did the generated tests run successfully in your test framework?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="slash-command-speed-run-q2" value="yes"> Yes</label><label><input type="radio" name="slash-command-speed-run-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Did you review and adjust any part of the generated tests before committing?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="slash-command-speed-run-q3" value="yes"> Yes</label><label><input type="radio" name="slash-command-speed-run-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li> <p><a href="https://code.visualstudio.com/docs/copilot/reference/copilot-vscode-features#_slash-commands">Copilot Chat slash commands reference</a></p> </li> <li> <p><a href="https://docs.github.com/en/copilot/using-github-copilot/guides-on-using-github-copilot/writing-tests-with-github-copilot">Generating tests with Copilot tutorial</a></p> </li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Slash @terminal debugging', N'<h3>Summary</h3> <p>In this debugging exercise you will intentionally break a script in your repository then use <strong>@terminal</strong> in GitHub Copilot Chat to diagnose and fix the failure. Expect to spend fifteen to twenty minutes.</p> <h3>What you will learn</h3> <ul> <li> <p>Capturing the last terminal command context with <code>@terminal</code>.</p> </li> <li> <p>Requesting an explanation of an error from Copilot.</p> </li> <li> <p>Accepting and applying an AI suggested fix.</p> </li> <li> <p>Verifying the script works after the fix.</p> </li> </ul> <h3>Prerequisites</h3> <p>Confirm Copilot Chat is enabled in <strong>your IDE</strong> such as VS Code, JetBrains, or Visual Studio. Open a repository that contains a script you can safely modify for example a Bash or Python utility.</p> <h3>Steps</h3> <ul> <li> <p><strong>Step 1.</strong> Open a script or a code file and introduce a simple error such as a misspelled variable name or missing import.</p> </li> <li> <p><strong>Step 2.</strong> Save the file then run the script or build the code in the integrated terminal.</p> </li> <li> <p><strong>Step 3.</strong> The script should fail and show an error message. Do not fix it manually.</p> </li> <li> <p><strong>Step 4.</strong> Open Copilot Chat and type <code>@terminal why did the last command fail</code> then press Enter.</p> </li> <li> <p><strong>Step 5.</strong> Read Copilot''s explanation and review the suggested fix (if any). If acceptable copy or accept the code into your script or code.</p> </li> <li> <p><strong>Step 6.</strong> Rerun the script or code with the same command. Confirm it now completes successfully.</p> </li> <li> <p><strong>Step 7.</strong> Commit the corrected script with a clear message drafted by you or suggested by Copilot.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did Copilot correctly explain the reason for the failure?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="slash-terminal-debugging-q1" value="yes"> Yes</label><label><input type="radio" name="slash-terminal-debugging-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did you apply the Copilot suggested fix without manual changes?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="slash-terminal-debugging-q2" value="yes"> Yes</label><label><input type="radio" name="slash-terminal-debugging-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Did the script run successfully after the fix?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="slash-terminal-debugging-q3" value="yes"> Yes</label><label><input type="radio" name="slash-terminal-debugging-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li><a href="https://code.visualstudio.com/docs/copilot/reference/copilot-vscode-features#_chat-tools">VS Code chat tools</a></li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Snippet translation', N'<h3>Summary</h3> <p>This exercise demonstrates how to use <strong>GitHub Copilot Chat</strong> to convert code from one language to another. You will copy a snippet from your repository for example Java ask Copilot Chat to translate it into Go idioms then place the result in a scrapbook branch for review. Plan about twenty minutes.</p> <h3>What you will learn</h3> <ul> <li> <p>Sending context aware prompts to Copilot Chat.</p> </li> <li> <p>Generating idiomatic code in a target language.</p> </li> <li> <p>Reviewing translated code for correctness and style.</p> </li> <li> <p>Isolating experiments in a scrapbook or draft branch.</p> </li> </ul> <h3>Prerequisites</h3> <p>Confirm Copilot Chat is active in <strong>your IDE</strong> such as VS Code JetBrains Visual Studio or Neovim. Ensure you have permissions to create a new branch in the repository you are using.</p> <h3>Steps</h3> <ul> <li> <p><strong>Step 1.</strong> Open a file that contains a non trivial snippet you want to translate for example a Java method.</p> </li> <li> <p><strong>Step 2.</strong> Highlight the entire snippet including any import statements that matter.</p> </li> <li> <p><strong>Step 3.</strong> Open Copilot Chat and type <code>Translate to Go idioms</code> then press Enter.</p> </li> <li> <p><strong>Step 4.</strong> Review the generated Go code. Use <strong>Tab</strong> to accept or <strong>Esc</strong> to ask follow up questions such as performance considerations.</p> </li> <li> <p><strong>Step 5.</strong> Create a scrapbook branch with <code>git checkout -b translate-experiment</code> or use your IDE branch controls.</p> </li> <li> <p><strong>Step 6.</strong> Add a new file for example <code>snippet.go</code> and paste the translated code. Run <code>go vet</code> or another linter to verify compilation.</p> </li> <li> <p><strong>Step 7.</strong> Commit the file with a descriptive message such as Add Go translation of example snippet.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did Copilot produce syntactically correct code in the target language?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="snippet-translation-q1" value="yes"> Yes</label><label><input type="radio" name="snippet-translation-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did the translated snippet compile or pass linting tools?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="snippet-translation-q2" value="yes"> Yes</label><label><input type="radio" name="snippet-translation-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Did you create and commit the translation in a separate scrapbook branch?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="snippet-translation-q3" value="yes"> Yes</label><label><input type="radio" name="snippet-translation-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li> <p><a href="https://docs.github.com/en/copilot/copilot-chat-cookbook/refactoring-code/translating-code-to-a-different-programming-language">Translating code across languages with Copilot</a></p> </li> <li> <p><a href="https://code.visualstudio.com/docs/copilot/overview">Copilot in VS Code documentation</a></p> </li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Spec Kit', N'<h3>Summary</h3> <p>In this exercise you will use <strong>Spec Kit</strong> (GitHub''s spec-driven development toolkit) to go from a natural-language idea to a fully implemented feature using structured specifications. Spec Kit bridges the gap between what you want to build and what AI agents implement. Expect to spend thirty to forty minutes.</p> <h3>What you will learn</h3> <ul> <li>Installing the <code>specify-cli</code> tool using <code>uv</code>.</li> <li>Initializing a Spec Kit project with <code>specify init</code>.</li> <li>Using slash commands to define a constitution, write specifications, generate plans, create tasks, and implement code.</li> <li>Following the spec-driven development workflow from idea to implementation.</li> </ul> <h3>Before you start</h3> <p>Ensure you have <strong>Python 3.11 or later</strong> and <strong>uv</strong> installed. You also need <strong>Git</strong> and a code editor with GitHub Copilot (VS Code recommended). Have a repository ready where you want to build a new feature.</p> <h3>Steps</h3> <ul> <li> <p><strong>Step 1.</strong> Install the Spec Kit CLI by running: <code>uv tool install specify-cli --from git+https://github.com/github/spec-kit.git</code></p> </li> <li> <p><strong>Step 2.</strong> Navigate to your repository and initialize Spec Kit: <code>specify init my-feature --ai copilot</code>. This creates a <code>.specs/</code> directory with the initial structure.</p> </li> <li> <p><strong>Step 3.</strong> Open Copilot Chat and run <code>/speckit.constitution</code> to define the project''s guiding principles and constraints. Review the generated constitution file in <code>.specs/</code>.</p> </li> <li> <p><strong>Step 4.</strong> Run <code>/speckit.specify</code> and describe the feature you want to build in natural language. Spec Kit converts your description into a structured specification with acceptance criteria.</p> </li> <li> <p><strong>Step 5.</strong> Run <code>/speckit.plan</code> to generate an implementation plan from the specification. Review the plan which breaks the work into ordered steps.</p> </li> <li> <p><strong>Step 6.</strong> Run <code>/speckit.tasks</code> to convert the plan into individual, actionable tasks that the agent can execute.</p> </li> <li> <p><strong>Step 7.</strong> Run <code>/speckit.implement</code> to have the agent execute each task and write the code. Review the generated code against the original specification to confirm it meets acceptance criteria.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did the specify init command create a .specs directory with the initial structure?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="spec-kit-q1" value="yes"> Yes</label><label><input type="radio" name="spec-kit-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did the /speckit.specify command produce a structured specification with acceptance criteria?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="spec-kit-q2" value="yes"> Yes</label><label><input type="radio" name="spec-kit-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Did /speckit.implement generate code that matched the planned specification?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="spec-kit-q3" value="yes"> Yes</label><label><input type="radio" name="spec-kit-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li> <p><a href="https://github.com/github/spec-kit">Spec Kit on GitHub</a></p> </li> <li> <p><a href="https://github.com/github/spec-kit/blob/main/docs/spec-driven.md">Spec-driven development overview</a></p> </li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Subagents', N'<h3>Summary</h3> <p>In this hands-on exercise you will delegate complex, multi-step tasks to <strong>subagents</strong> in GitHub Copilot. A subagent is an isolated agent session that the primary agent spawns to perform focused research or implementation work, then returns a summary. Expect to spend twenty to thirty minutes.</p> <h3>What you will learn</h3> <ul> <li>Understanding how subagents provide isolated context for subtasks.</li> <li>Prompting the primary/default agent so it delegates work to a subagent automatically.</li> <li>Observing parallel subagent execution in the Copilot Chat panel.</li> <li>Using a custom agent definition to act as a reusable subagent.</li> </ul> <h3>Before you start</h3> <p>Ensure you are running VS Code with the latest GitHub Copilot Chat extension. Agent mode must be enabled in settings (<code>chat.agent.enabled</code>). Open a repository that contains multiple files or modules so the agent has enough complexity to benefit from delegation.</p> <h3>Steps</h3> <ul> <li> <p><strong>Step 1.</strong> Open a Local Copilot Chat session and switch to <strong>Agent</strong> mode using the agents dropdown at the bottom of the panel.</p> </li> <li> <p><strong>Step 2.</strong> Enter a prompt that naturally requires delegation, for example: <code>Review the entire codebase and perform an extensive research across all the public API endpoints in this project in parallel and then create a Markdown summary for each API endpoint that provides the following details - HTTP method, route, purpose, and enhancements.</code></p> </li> </ul> <p><strong>NOTE:</strong> VS Code automatically (optionally) invokes built-in subagents depending on the task. If you don''t see the subagents being automatically, you can try adding this to the prompt <code>Leverage subagents if needed</code>. <strong>Tip</strong> - Retry the task with a complex task involving the entire repo if this still doesn''t work!</p> <ul> <li> <p><strong>Step 3.</strong> Watch the Chat panel. The agent should spawn a subagent to research the codebase. You will see a collapsed <strong>Subagent</strong> node appear with its own tool calls and progress indicator.</p> </li> <li> <p><strong>Step 4.</strong> Expand the subagent node to inspect what tools it called and the summary it returned to the primary agent.</p> </li> <li> <p><strong>Step 5.</strong> Now create a custom agent file at <code>.github/agents/researcher.md</code> with the following content: a description instructing it to search the codebase and return concise findings, and an <code>agents</code> front-matter field to allow it to be invoked as a subagent.</p> </li> <li> <p><strong>Step 6.</strong> In a new chat session, prompt the agent to use your custom researcher agent: <code>@researcher Find all TODO comments across the project and categorize them by priority.</code></p> </li> <li> <p><strong>Step 7.</strong> Verify the custom agent is executed as a subagent and returned structured results to the primary conversation.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did the primary agent spawn a subagent that appeared as a collapsed node in the Chat panel?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="subagents-q1" value="yes"> Yes</label><label><input type="radio" name="subagents-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Were you able to expand and inspect the subagent tool calls and returned summary?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="subagents-q2" value="yes"> Yes</label><label><input type="radio" name="subagents-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Did the custom agent file work as a reusable subagent when invoked with the at-mention?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="subagents-q3" value="yes"> Yes</label><label><input type="radio" name="subagents-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li> <p><a href="https://code.visualstudio.com/docs/copilot/agents/subagents">Subagents in VS Code</a></p> </li> <li> <p><a href="https://code.visualstudio.com/docs/copilot/customization/custom-agents">Custom agents overview</a></p> </li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Vision driven UX prototype', N'<h3>Summary</h3> <p>In this rapid prototyping exercise, you will upload a photo of a hand-drawn or externally sourced wireframe into GitHub Copilot Chat Vision Preview and request Copilot to generate responsive HTML and CSS. Reserve twenty minutes for the full flow.</p> <h3>What you will learn</h3> <ul> <li> <p>Adding image context to Copilot Chat Vision/Images (Preview feature).</p> </li> <li> <p>Prompting Copilot to scaffold HTML and CSS from a wireframe.</p> </li> <li> <p>Saving generated files in a prototype folder.</p> </li> <li> <p>Launching a local preview to test responsiveness.</p> </li> </ul> <h3>Before you start</h3> <p><strong>Copilot Chat Vision is currently in Preview and the preview features must be enabled in the Enterprise/Organization policy</strong>. Place a photo or scan of your wireframe in the repository for example <code>docs/wireframe.jpg</code>.</p> <h3>Steps</h3> <ul> <li> <p><strong>Step 1.</strong> Create a new branch called <code>vision-prototype</code> with <code>git checkout -b vision-prototype</code> or the source control panel.</p> </li> <li> <p><strong>Step 2.</strong> Open Copilot Chat in VS Code in Agent mode and drag the wireframe image into the chat box. Wait until the thumbnail appears. Example:</p> </li> <li> <p><strong>Step 3.</strong> Type <code>Scaffold responsive HTML and CSS for this layout place files in prototype folder</code> then press Enter.</p> </li> <li> <p><strong>Step 4.</strong> Copilot agent returns one or more files. Accept the generated files so they appear under <code>prototype/</code>.</p> </li> <li> <p><strong>Step 5.</strong> Open <code>prototype/index.html</code> in the Live Preview extension or a local browser. Resize the window to confirm the layout adapts to mobile and desktop widths.</p> </li> <li> <p><strong>Step 6.</strong> Adjust colours fonts or breakpoints if needed then save the files.</p> </li> <li> <p><strong>Step 7.</strong> Commit the prototype with a clear message and push the branch for review.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did Copilot generate HTML and CSS files in the <code>prototype/</code> folder?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="vision-driven-ux-prototype-q1" value="yes"> Yes</label><label><input type="radio" name="vision-driven-ux-prototype-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Does the prototype render correctly on both mobile width and desktop width?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="vision-driven-ux-prototype-q2" value="yes"> Yes</label><label><input type="radio" name="vision-driven-ux-prototype-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Did you commit the files on the <code>vision-prototype</code> branch?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="vision-driven-ux-prototype-q3" value="yes"> Yes</label><label><input type="radio" name="vision-driven-ux-prototype-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li> <p><a href="https://docs.github.com/en/copilot/how-tos/chat-with-copilot/chat-in-ide#using-images-in-copilot-chat">Using images in Copilot Chat</a></p> </li> <li> <p><a href="https://code.visualstudio.com/docs/copilot/chat/chat-agent-mode">Copilot Chat agent mode</a></p> </li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Vision preview quick win', N'<h3>Summary</h3> <p>In this quick win you will use <strong>GitHub Copilot Chat Vision (Preview feature)</strong> to turn an existing architecture diagram into C#/Java/JS code stubs. You will drag a PNG or SVG diagram from your repository into the chat panel ask Copilot to stub each service or class then save the generated files. The whole task should take fifteen to twenty minutes.</p> <h3>What you will learn</h3> <ul> <li> <p>Adding image context to Copilot Chat Vision Preview.</p> </li> <li> <p>Prompting Copilot to create class and interface stubs from a diagram.</p> </li> <li> <p>Saving generated files in the correct folder of your repo.</p> </li> <li> <p>Using a scratch branch to keep experiments separate from main.</p> </li> </ul> <h3>Prerequisites</h3> <p><strong>Copilot Chat Vision is currently in Preview and the preview features must be enabled in the Enterprise/Organization policy</strong>. Verify you have the latest VS Code and Copilot extension then enable the Vision feature in the extension settings. Make sure the diagram you want to use is already stored in your repository for example <code>docs/system-architecture.png</code>.</p> <h3>Steps</h3> <ul> <li> <p><strong>Step 1.</strong> Open the architecture image in the VS Code Explorer so you can see it in the file list.</p> </li> <li> <p><strong>Step 2.</strong> Create and check out a new branch named <code>vision-stubs</code> by using <code>git checkout -b vision-stubs</code> or the source control view.</p> </li> <li> <p><strong>Step 3.</strong> Open a new Local Copilot Chat session and select <strong>Agent</strong> mode.</p> </li> <li> <p><strong>Step 4.</strong> Drag the PNG or SVG diagram from the Explorer into the chat input box. Wait until the thumbnail appears confirming the image is attached.</p> </li> <li> <p><strong>Step 5.</strong> Type <code>Stub these services/classes</code>in a language of your choice and press Enter. Copilot will list the detected elements and generate code stubs for each one.</p> </li> <li> <p><strong>Step 6.</strong> Review the output. Accept the files generated by Copilot or copy each stub into new files under <code>/src/</code>.</p> </li> <li> <p><strong>Step 7.</strong> Compile the code or your usual build task to ensure the new files compile.</p> </li> <li> <p><strong>Step 8.</strong> Commit the stubs to the <code>vision-stubs</code> branch with a descriptive message created by you or drafted by Copilot.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did Copilot identify every main component in your diagram?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="vision-preview-quick-win-q1" value="yes"> Yes</label><label><input type="radio" name="vision-preview-quick-win-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did all generated stubs compile without errors?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="vision-preview-quick-win-q2" value="yes"> Yes</label><label><input type="radio" name="vision-preview-quick-win-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Did you commit the stubs in a separate branch for later review?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="vision-preview-quick-win-q3" value="yes"> Yes</label><label><input type="radio" name="vision-preview-quick-win-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li><a href="https://docs.github.com/en/copilot/how-tos/chat-with-copilot/chat-in-ide#using-images-in-copilot-chat">Copilot Vision/Images</a></li> </ul>', SYSDATETIME(), 12);
INSERT INTO [dbo].[Challenges] (Title, Content, PostedDate, ActivityId) VALUES (N'Workspace autopilot', N'<h3>Summary</h3> <p>In this activity you will use <strong>GitHub Copilot coding agent</strong> to fix a real issue in your repository. You will assign Copilot to a GitHub Issue, and it will autonomously create a branch, implement the fix, and open a pull request for your review. Expect to spend twenty to twenty-five minutes.</p> <h3>What you will learn</h3> <ul> <li> <p>Assigning Copilot coding agent to a GitHub Issue.</p> </li> <li> <p>Reviewing the pull request that Copilot creates autonomously.</p> </li> <li> <p>Providing feedback via pull request comments to iterate on the solution.</p> </li> <li> <p>Merging the pull request after verifying the fix.</p> </li> </ul> <h3>Before you start</h3> <p>Copilot coding agent is available with <strong>GitHub Copilot Pro, Pro+, Business, and Enterprise</strong> plans. Confirm that Copilot coding agent is enabled for your repository (an organization admin may need to enable the policy). Ensure there is a GitHub Issue in your repository that describes a reproducible bug.</p> <h3>Steps</h3> <ul> <li> <p><strong>Step 1.</strong> Open the Issue you want to fix on GitHub.com and click <strong>Assignees</strong> in the right sidebar.</p> </li> <li> <p><strong>Step 2.</strong> Select <strong>Copilot</strong> from the assignees list. In the dialog that appears, optionally add specific guidance in the <strong>Optional prompt</strong> field (for example, coding patterns to follow or files to modify).</p> </li> <li> <p><strong>Step 3.</strong> Confirm the target repository and base branch, then click to assign. Copilot coding agent begins working in the background using a GitHub Actions-powered environment.</p> </li> <li> <p><strong>Step 4.</strong> Monitor progress from the <strong>Agents</strong> tab in your repository or from the <a href="https://github.com/copilot/agents">agents page</a>. Copilot will create a <code>copilot/</code> branch, commit changes, and open a draft pull request.</p> </li> <li> <p><strong>Step 5.</strong> When Copilot finishes, it requests a review from you. Open the pull request, review the diff, and run tests locally or via CI to confirm the bug is resolved.</p> </li> <li> <p><strong>Step 6.</strong> If changes are needed, leave pull request comments — Copilot will read them and push follow-up commits. Iterate until you are satisfied.</p> </li> <li> <p><strong>Step 7.</strong> Approve and merge the pull request. Close the original Issue if it did not close automatically.</p> </li> </ul> <h3>Checkpoint</h3> <div class="question-item"><ol> <li>Did Copilot coding agent create a pull request from the assigned Issue?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="workspace-autopilot-q1" value="yes"> Yes</label><label><input type="radio" name="workspace-autopilot-q1" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="2"> <li>Did the automated branch and pull request compile and pass tests?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="workspace-autopilot-q2" value="yes"> Yes</label><label><input type="radio" name="workspace-autopilot-q2" value="no"> No</label></div></li> </ol></div> <div class="question-item"><ol start="3"> <li>Did you merge the pull request and close the Issue?<div class="radio-group" style="margin-left:1.5em;margin-top:6px;"><label><input type="radio" name="workspace-autopilot-q3" value="yes"> Yes</label><label><input type="radio" name="workspace-autopilot-q3" value="no"> No</label></div></li> </ol></div> <h3>Explore more</h3> <ul> <li> <p><a href="https://docs.github.com/en/copilot/concepts/agents/coding-agent/about-coding-agent">About GitHub Copilot coding agent</a></p> </li> <li> <p><a href="https://docs.github.com/en/copilot/how-tos/use-copilot-agents/coding-agent/create-a-pr">Asking GitHub Copilot to create a pull request</a></p> </li> </ul>', SYSDATETIME(), 12);
